INSERT INTO learning_content_items
  (section, content_key, level_key, goal_key, title, description, payload_json, sort_order, status)
VALUES
  ('reading', 'schedule-change', 'easy', NULL, 'Schedule Change', 'Chủ đề: thay đổi lịch họp và chuẩn bị báo cáo.', '{"id":"schedule-change","level":"easy","title":"Schedule Change","description":"Chủ đề: thay đổi lịch họp và chuẩn bị báo cáo.","lines":[["A: Hi Karen, have you seen the updated schedule for tomorrow''s product briefing?","A: Chào Karen, bạn đã xem lịch cập nhật cho buổi họp giới thiệu sản phẩm ngày mai chưa?"],["B: Not yet. Was there a change?","B: Chưa. Có thay đổi gì à?"],["A: Yes, the meeting has been moved from 10 a.m. to 1:30 p.m. because the regional manager''s flight was delayed.","A: Có, cuộc họp đã được chuyển từ 10 giờ sáng sang 1 giờ 30 chiều vì chuyến bay của quản lý khu vực bị hoãn."],["B: Thanks for letting me know. Should I still bring the quarterly sales report?","B: Cảm ơn đã báo cho tôi biết. Tôi vẫn nên mang báo cáo doanh số theo quý chứ?"],["A: Definitely. Mr. Lawson wants to review the latest figures before we finalize next month''s marketing plan.","A: Chắc chắn rồi. Ông Lawson muốn xem lại các số liệu mới nhất trước khi chúng ta chốt kế hoạch marketing tháng tới."],["B: Understood. I''ll make sure the numbers are updated and printed before lunch.","B: Đã hiểu. Tôi sẽ đảm bảo các số liệu được cập nhật và in ra trước bữa trưa."]],"vocab":["updated schedule = lịch đã cập nhật","product briefing = buổi họp giới thiệu sản phẩm","regional manager = quản lý khu vực","quarterly sales report = báo cáo doanh số theo quý","finalize = hoàn tất / chốt lại"]}', 1, 'published'),
  ('reading', 'office-supplies', 'easy', NULL, 'Office Supplies', 'Chủ đề: kiểm tra văn phòng phẩm cho buổi đào tạo.', '{"id":"office-supplies","level":"easy","title":"Office Supplies","description":"Chủ đề: kiểm tra văn phòng phẩm cho buổi đào tạo.","lines":[["A: Mark, do we still have enough folders and printer paper for the training session this afternoon?","A: Mark, chúng ta còn đủ bìa hồ sơ và giấy in cho buổi đào tạo chiều nay không?"],["B: We have plenty of paper, but we''re running low on folders. I only found about fifteen in the storage room.","B: Giấy thì còn nhiều, nhưng bìa hồ sơ sắp hết. Tôi chỉ tìm thấy khoảng mười lăm cái trong phòng chứa đồ."],["A: That won''t be enough. We''re expecting at least thirty participants.","A: Như vậy sẽ không đủ. Chúng ta dự kiến có ít nhất ba mươi người tham gia."],["B: I can stop by the supply store during my lunch break and pick up some extra ones.","B: Tôi có thể ghé cửa hàng văn phòng phẩm trong giờ nghỉ trưa và mua thêm một ít."],["A: That would be very helpful. Please also get a few packs of name tags if they''re available.","A: Như vậy sẽ rất hữu ích. Nếu có, hãy mua thêm vài gói bảng tên nữa nhé."],["B: No problem. I''ll keep the receipt and submit it with my expense report.","B: Không vấn đề gì. Tôi sẽ giữ hóa đơn và nộp kèm báo cáo chi phí."]],"vocab":["running low on = sắp hết","storage room = phòng chứa đồ","participants = người tham gia","name tags = bảng tên","submit a receipt = nộp hóa đơn"]}', 2, 'published'),
  ('reading', 'client-visit', 'easy', NULL, 'Client Visit', 'Chủ đề: chuẩn bị phòng họp và đón khách hàng.', '{"id":"client-visit","level":"easy","title":"Client Visit","description":"Chủ đề: chuẩn bị phòng họp và đón khách hàng.","lines":[["A: Good morning, Lisa. Are we ready for the clients from Brighton Consulting?","A: Chào buổi sáng, Lisa. Chúng ta đã sẵn sàng đón khách từ Brighton Consulting chưa?"],["B: Almost. I''ve prepared the conference room and tested the projector, but the catering order hasn''t arrived yet.","B: Gần xong rồi. Tôi đã chuẩn bị phòng họp và kiểm tra máy chiếu, nhưng đơn đồ ăn/thức uống vẫn chưa đến."],["A: Did the restaurant confirm the delivery time?","A: Nhà hàng đã xác nhận thời gian giao chưa?"],["B: Yes, they said it should be here within twenty minutes. I ordered coffee, tea, bottled water, and some light refreshments.","B: Rồi, họ nói đơn sẽ đến trong vòng hai mươi phút. Tôi đã đặt cà phê, trà, nước đóng chai và một ít đồ ăn nhẹ."],["A: Excellent. Since this is their first visit, we want to make a polished impression.","A: Tuyệt. Vì đây là lần đầu họ đến, chúng ta muốn tạo ấn tượng chuyên nghiệp và chỉn chu."],["B: Absolutely. I''ll also place the company brochures near the entrance.","B: Chắc chắn rồi. Tôi cũng sẽ đặt tài liệu giới thiệu công ty gần lối vào."]],"vocab":["catering order = đơn đặt đồ ăn/thức uống cho sự kiện","light refreshments = đồ ăn nhẹ","polished impression = ấn tượng chuyên nghiệp, chỉn chu","company brochures = tài liệu giới thiệu công ty","near the entrance = gần lối vào"]}', 3, 'published'),
  ('reading', 'delivery-delay', 'easy', NULL, 'Delivery Delay', 'Chủ đề: hỏi tình trạng đơn hàng bị giao trễ.', '{"id":"delivery-delay","level":"easy","title":"Delivery Delay","description":"Chủ đề: hỏi tình trạng đơn hàng bị giao trễ.","lines":[["A: Hello, this is Daniel from Westbrook Electronics. I''m calling about our order placed last Monday.","A: Xin chào, tôi là Daniel từ Westbrook Electronics. Tôi gọi về đơn hàng chúng tôi đã đặt vào thứ Hai tuần trước."],["B: Good afternoon, Mr. Daniel. Let me check the status for you. Do you have the order number?","B: Chào buổi chiều, ông Daniel. Để tôi kiểm tra tình trạng cho ông. Ông có mã đơn hàng không?"],["A: Yes, it''s WB-4729. We were expecting the shipment yesterday, but nothing has arrived.","A: Có, mã là WB-4729. Chúng tôi dự kiến nhận lô hàng hôm qua, nhưng vẫn chưa có gì đến."],["B: I apologize for the inconvenience. It looks like the package was held up at the distribution center due to a labeling issue.","B: Tôi xin lỗi vì sự bất tiện này. Có vẻ kiện hàng bị giữ lại ở trung tâm phân phối do vấn đề nhãn hàng."],["A: When can we expect it to be delivered?","A: Khi nào chúng tôi có thể nhận được hàng?"],["B: The issue has been resolved, and the shipment is scheduled to arrive by tomorrow afternoon.","B: Vấn đề đã được giải quyết, và lô hàng dự kiến đến vào chiều mai."]],"vocab":["placed an order = đặt hàng","shipment = lô hàng","held up = bị trì hoãn","distribution center = trung tâm phân phối","labeling issue = vấn đề về nhãn hàng"]}', 4, 'published'),
  ('reading', 'hotel-reservation', 'easy', NULL, 'Hotel Reservation', 'Chủ đề: nhận phòng khách sạn và hỏi giờ ăn sáng.', '{"id":"hotel-reservation","level":"easy","title":"Hotel Reservation","description":"Chủ đề: nhận phòng khách sạn và hỏi giờ ăn sáng.","lines":[["A: Good evening. I have a reservation under the name Thompson.","A: Chào buổi tối. Tôi có đặt phòng dưới tên Thompson."],["B: Welcome, Mr. Thompson. Let me pull up your booking. You''ll be staying with us for three nights, correct?","B: Chào mừng ông Thompson. Để tôi mở thông tin đặt phòng của ông. Ông sẽ ở lại ba đêm, đúng không ạ?"],["A: That''s right. I also requested a quiet room away from the elevator.","A: Đúng vậy. Tôi cũng đã yêu cầu một phòng yên tĩnh, xa thang máy."],["B: Yes, we''ve arranged a room on the eighth floor facing the courtyard. It should be very quiet.","B: Vâng, chúng tôi đã sắp xếp một phòng ở tầng tám nhìn ra sân trong. Phòng đó sẽ rất yên tĩnh."],["A: Wonderful. Could you tell me what time breakfast is served?","A: Tuyệt vời. Bạn có thể cho tôi biết bữa sáng được phục vụ lúc mấy giờ không?"],["B: Certainly. Breakfast is available from 6:30 to 10 a.m. in the restaurant next to the lobby.","B: Tất nhiên. Bữa sáng có từ 6:30 đến 10 giờ sáng tại nhà hàng cạnh sảnh."]],"vocab":["reservation under the name = đặt phòng dưới tên","pull up your booking = mở thông tin đặt phòng","away from the elevator = xa thang máy","facing the courtyard = nhìn ra sân trong","breakfast is served = bữa sáng được phục vụ"]}', 5, 'published'),
  ('reading', 'job-interview-easy', 'easy', NULL, 'Job Interview', 'Chủ đề: ứng viên đến phỏng vấn và chuẩn bị hồ sơ.', '{"id":"job-interview-easy","level":"easy","title":"Job Interview","description":"Chủ đề: ứng viên đến phỏng vấn và chuẩn bị hồ sơ.","lines":[["A: Has the candidate for the marketing assistant position arrived yet?","A: Ứng viên cho vị trí trợ lý marketing đã đến chưa?"],["B: Yes, she checked in at reception about five minutes ago.","B: Rồi, cô ấy đã báo có mặt ở quầy lễ tân khoảng năm phút trước."],["A: Great. Did she bring a printed copy of her resume?","A: Tốt. Cô ấy có mang bản in CV không?"],["B: She did, and she also brought a portfolio with samples from her previous internship.","B: Có, và cô ấy cũng mang theo portfolio có các mẫu từ kỳ thực tập trước."],["A: That''s impressive. Please ask her to wait in Meeting Room 2 while I finish this phone call.","A: Ấn tượng đấy. Hãy mời cô ấy chờ ở Phòng họp 2 trong lúc tôi kết thúc cuộc gọi này."],["B: Of course. I''ll offer her some water and let her know you''ll be with her shortly.","B: Tất nhiên. Tôi sẽ mời cô ấy nước và báo rằng anh/chị sẽ gặp cô ấy ngay."]],"vocab":["candidate = ứng viên","checked in at reception = đã báo có mặt ở quầy lễ tân","resume = sơ yếu lý lịch / CV","portfolio = hồ sơ sản phẩm cá nhân","previous internship = kỳ thực tập trước"]}', 6, 'published'),
  ('reading', 'software-update', 'easy', NULL, 'Software Update', 'Chủ đề: cập nhật phần mềm và tránh gián đoạn công việc.', '{"id":"software-update","level":"easy","title":"Software Update","description":"Chủ đề: cập nhật phần mềm và tránh gián đoạn công việc.","lines":[["A: Hi Steven, have you installed the latest software update yet?","A: Chào Steven, bạn đã cài bản cập nhật phần mềm mới nhất chưa?"],["B: Not yet. I saw the notification, but I was worried it might interrupt my work.","B: Chưa. Tôi đã thấy thông báo, nhưng lo rằng nó có thể làm gián đoạn công việc."],["A: It only takes about ten minutes, and the IT department recommends installing it today.","A: Nó chỉ mất khoảng mười phút, và bộ phận IT khuyên nên cài trong hôm nay."],["B: Does it include any major changes?","B: Nó có thay đổi lớn nào không?"],["A: Mostly security improvements and a few new tools for managing customer data more efficiently.","A: Chủ yếu là cải tiến bảo mật và vài công cụ mới để quản lý dữ liệu khách hàng hiệu quả hơn."],["B: In that case, I''ll install it during my afternoon break so it doesn''t affect my current project.","B: Nếu vậy, tôi sẽ cài trong giờ nghỉ chiều để không ảnh hưởng đến dự án hiện tại."]],"vocab":["software update = bản cập nhật phần mềm","notification = thông báo","interrupt my work = làm gián đoạn công việc","security improvements = cải tiến bảo mật","efficiently = một cách hiệu quả"]}', 7, 'published'),
  ('reading', 'restaurant-booking', 'easy', NULL, 'Restaurant Booking', 'Chủ đề: xác nhận đặt bàn và yêu cầu món chay.', '{"id":"restaurant-booking","level":"easy","title":"Restaurant Booking","description":"Chủ đề: xác nhận đặt bàn và yêu cầu món chay.","lines":[["A: Hi, I''d like to confirm a dinner reservation for this Friday evening.","A: Xin chào, tôi muốn xác nhận đặt bàn ăn tối vào tối thứ Sáu này."],["B: Certainly. May I have the name on the reservation?","B: Tất nhiên. Cho tôi xin tên trên đặt chỗ được không?"],["A: It''s under Rachel Morgan, for eight people at 7 p.m.","A: Dưới tên Rachel Morgan, cho tám người lúc 7 giờ tối."],["B: Yes, I see it here. You requested a private table for a business dinner, correct?","B: Vâng, tôi thấy rồi. Bà yêu cầu bàn riêng cho bữa tối công việc, đúng không ạ?"],["A: Exactly. Also, one of our guests is vegetarian. Would it be possible to prepare a suitable option?","A: Đúng vậy. Ngoài ra, một khách của chúng tôi ăn chay. Có thể chuẩn bị một lựa chọn phù hợp không?"],["B: Absolutely. Our chef can prepare a vegetarian entree, and I''ll make a note of that on your reservation.","B: Chắc chắn. Đầu bếp của chúng tôi có thể chuẩn bị món chính chay, và tôi sẽ ghi chú điều đó vào đặt chỗ của bà."]],"vocab":["confirm a reservation = xác nhận đặt chỗ","private table = bàn riêng","business dinner = bữa tối công việc","vegetarian = người ăn chay","make a note of that = ghi chú điều đó lại"]}', 8, 'published'),
  ('reading', 'store-return', 'easy', NULL, 'Store Return', 'Chủ đề: trả hàng, hoàn tiền hoặc đổi sản phẩm.', '{"id":"store-return","level":"easy","title":"Store Return","description":"Chủ đề: trả hàng, hoàn tiền hoặc đổi sản phẩm.","lines":[["A: Excuse me, I''d like to return this jacket. I bought it last week, but the zipper doesn''t work properly.","A: Xin lỗi, tôi muốn trả lại chiếc áo khoác này. Tôi mua nó tuần trước, nhưng khóa kéo không hoạt động đúng."],["B: I''m sorry about that. Do you still have the receipt?","B: Tôi rất tiếc về việc đó. Bạn còn giữ hóa đơn không?"],["A: Yes, here it is. I only wore it once and noticed the problem this morning.","A: Có, đây ạ. Tôi chỉ mặc một lần và phát hiện vấn đề sáng nay."],["B: Thank you. Since the item is defective, we can offer you a full refund or an exchange.","B: Cảm ơn. Vì sản phẩm bị lỗi, chúng tôi có thể hoàn tiền đầy đủ hoặc đổi hàng cho bạn."],["A: I''d prefer an exchange if you still have the same jacket in a medium size.","A: Tôi muốn đổi hàng nếu cửa hàng còn chiếc áo giống vậy cỡ M."],["B: Let me check our inventory. It looks like we have one left in navy blue.","B: Để tôi kiểm tra kho. Có vẻ chúng tôi còn một chiếc màu xanh navy."]],"vocab":["return this jacket = trả lại áo khoác","zipper = khóa kéo","receipt = hóa đơn","defective = bị lỗi","full refund = hoàn tiền đầy đủ","exchange = đổi hàng"]}', 9, 'published'),
  ('reading', 'project-deadline', 'easy', NULL, 'Project Deadline', 'Chủ đề: hoàn thiện bài thuyết trình trước hạn chót.', '{"id":"project-deadline","level":"easy","title":"Project Deadline","description":"Chủ đề: hoàn thiện bài thuyết trình trước hạn chót.","lines":[["A: Maria, how is the client presentation coming along?","A: Maria, bài thuyết trình cho khách hàng tiến triển thế nào rồi?"],["B: It''s nearly finished. I just need to revise the introduction and add the updated budget figures.","B: Gần xong rồi. Tôi chỉ cần chỉnh phần mở đầu và thêm số liệu ngân sách đã cập nhật."],["A: Good. The deadline is tomorrow morning, so we should review everything before the end of the day.","A: Tốt. Hạn chót là sáng mai, nên chúng ta nên xem lại mọi thứ trước cuối ngày."],["B: I agree. I''ll send you the latest version by 3 p.m.","B: Tôi đồng ý. Tôi sẽ gửi anh/chị phiên bản mới nhất trước 3 giờ chiều."],["A: Perfect. I''ll check the slides for clarity and make sure the main points are easy to follow.","A: Hoàn hảo. Tôi sẽ kiểm tra slide để đảm bảo rõ ràng và các ý chính dễ theo dõi."],["B: Thanks. Once you give me your feedback, I''ll make the final adjustments.","B: Cảm ơn. Sau khi nhận phản hồi, tôi sẽ thực hiện các chỉnh sửa cuối cùng."]],"vocab":["coming along = tiến triển thế nào","nearly finished = gần hoàn thành","revise = chỉnh sửa","updated budget figures = số liệu ngân sách đã cập nhật","clarity = sự rõ ràng","final adjustments = chỉnh sửa cuối cùng"]}', 10, 'published'),
  ('reading', 'office-renovation', 'medium', NULL, 'Memo - Office Renovation', 'Chủ đề: thông báo lịch sửa sảnh chính.', '{"id":"office-renovation","level":"medium","title":"Memo - Office Renovation","description":"Chủ đề: thông báo lịch sửa sảnh chính.","lines":[["To: All Staff","Gửi: Toàn thể nhân viên"],["From: Facilities Department","Từ: Bộ phận Cơ sở vật chất"],["Subject: Lobby Renovation Schedule","Chủ đề: Lịch sửa chữa sảnh chính"],["Please be advised that renovation work in the main lobby will begin on Monday, June 8.","Xin lưu ý rằng công việc sửa chữa tại sảnh chính sẽ bắt đầu vào thứ Hai, ngày 8 tháng 6."],["During the first week, the front entrance will be temporarily closed, and employees should use the side entrance near the parking area.","Trong tuần đầu tiên, lối vào phía trước sẽ tạm thời đóng, và nhân viên nên dùng lối bên cạnh khu vực đậu xe."],["Visitors must check in at the temporary reception desk on the second floor.","Khách đến phải làm thủ tục tại quầy lễ tân tạm thời ở tầng hai."],["We apologize for any inconvenience and appreciate your cooperation.","Chúng tôi xin lỗi vì bất kỳ bất tiện nào và cảm ơn sự hợp tác của quý vị."]],"vocab":["renovation = sửa chữa/cải tạo","temporarily = tạm thời","check in = làm thủ tục/báo có mặt","inconvenience = sự bất tiện","cooperation = sự hợp tác","Please be advised that... = Xin lưu ý rằng..."]}', 11, 'published'),
  ('reading', 'delayed-shipment-email', 'medium', NULL, 'Email - Delayed Shipment', 'Chủ đề: email thông báo đơn hàng bị trễ.', '{"id":"delayed-shipment-email","level":"medium","title":"Email - Delayed Shipment","description":"Chủ đề: email thông báo đơn hàng bị trễ.","lines":[["Subject: Update on Order #4582","Chủ đề: Cập nhật về đơn hàng #4582"],["Dear Ms. Carter,","Kính gửi bà Carter,"],["We regret to inform you that your recent order has been delayed due to an unexpected shortage at our distribution center.","Chúng tôi rất tiếc phải thông báo rằng đơn hàng gần đây của bà bị trì hoãn do tình trạng thiếu hàng ngoài dự kiến tại trung tâm phân phối."],["The items are now expected to ship by Friday, and we will send you a tracking number as soon as they leave our warehouse.","Các mặt hàng hiện dự kiến được gửi đi trước thứ Sáu, và chúng tôi sẽ gửi mã theo dõi ngay khi hàng rời kho."],["As a courtesy, we have waived the delivery fee.","Như một sự hỗ trợ thiện chí, chúng tôi đã miễn phí giao hàng."],["Sincerely, Customer Support Team","Trân trọng, Đội ngũ Hỗ trợ Khách hàng"]],"vocab":["regret to inform = rất tiếc phải thông báo","shortage = sự thiếu hụt","distribution center = trung tâm phân phối","warehouse = kho hàng","waive the fee = miễn phí","As a courtesy... = Như một sự hỗ trợ/thiện chí..."]}', 12, 'published'),
  ('reading', 'training-workshop', 'medium', NULL, 'Notice - Training Workshop', 'Chủ đề: thông báo workshop phát triển chuyên môn.', '{"id":"training-workshop","level":"medium","title":"Notice - Training Workshop","description":"Chủ đề: thông báo workshop phát triển chuyên môn.","lines":[["Professional Development Workshop","Hội thảo Phát triển Chuyên môn"],["A two-hour workshop on effective client communication will be held next Tuesday in Room 405.","Một hội thảo kéo dài hai giờ về giao tiếp hiệu quả với khách hàng sẽ được tổ chức vào thứ Ba tới tại Phòng 405."],["The session will cover email etiquette, phone call strategies, and techniques for handling difficult customers.","Buổi học sẽ bao gồm phép lịch sự trong email, chiến lược gọi điện và kỹ thuật xử lý khách hàng khó tính."],["Employees who work directly with clients are strongly encouraged to attend.","Nhân viên làm việc trực tiếp với khách hàng được khuyến khích mạnh mẽ tham dự."],["Registration closes at 5 p.m. on Friday.","Hạn đăng ký kết thúc lúc 5 giờ chiều thứ Sáu."]],"vocab":["professional development = phát triển chuyên môn","etiquette = phép lịch sự/quy tắc ứng xử","handle difficult customers = xử lý khách hàng khó tính","encouraged to attend = được khuyến khích tham dự","Registration closes at... = Hạn đăng ký kết thúc lúc..."]}', 13, 'published'),
  ('reading', 'local-business-cafe', 'medium', NULL, 'Short Article - Local Business', 'Chủ đề: bài báo ngắn về quán cà phê mới.', '{"id":"local-business-cafe","level":"medium","title":"Short Article - Local Business","description":"Chủ đề: bài báo ngắn về quán cà phê mới.","lines":[["New Cafe Opens Near Central Station","Quán cà phê mới mở gần Ga Trung tâm"],["A locally owned cafe has opened across from Central Station, offering commuters a convenient place to grab breakfast and coffee before work.","Một quán cà phê do người địa phương sở hữu đã mở đối diện Ga Trung tâm, mang đến cho người đi làm một nơi tiện lợi để mua bữa sáng và cà phê trước giờ làm."],["The owner, Maria Lopez, says the shop focuses on fresh pastries, quick service, and reasonable prices.","Chủ quán, Maria Lopez, cho biết cửa hàng tập trung vào bánh ngọt tươi, phục vụ nhanh và giá cả hợp lý."],["To attract first-time customers, the cafe is offering a 20 percent discount throughout its opening week.","Để thu hút khách hàng lần đầu, quán đang giảm giá 20 phần trăm trong suốt tuần khai trương."]],"vocab":["locally owned = do người địa phương sở hữu","commuter = người đi làm/đi học hằng ngày","reasonable prices = giá cả hợp lý","first-time customers = khách hàng lần đầu","To attract first-time customers... = Để thu hút khách hàng lần đầu..."]}', 14, 'published'),
  ('reading', 'remote-work-policy', 'medium', NULL, 'Memo - Policy Update', 'Chủ đề: cập nhật chính sách làm việc từ xa.', '{"id":"remote-work-policy","level":"medium","title":"Memo - Policy Update","description":"Chủ đề: cập nhật chính sách làm việc từ xa.","lines":[["To: Department Managers","Gửi: Các trưởng bộ phận"],["Subject: Updated Remote Work Policy","Chủ đề: Chính sách làm việc từ xa đã cập nhật"],["Starting July 1, employees may work remotely up to two days per week, provided that their supervisors approve the arrangement in advance.","Bắt đầu từ ngày 1 tháng 7, nhân viên có thể làm việc từ xa tối đa hai ngày mỗi tuần, với điều kiện cấp trên phê duyệt sắp xếp này trước."],["Team meetings should continue to be held in person whenever possible.","Các cuộc họp nhóm vẫn nên được tổ chức trực tiếp khi có thể."],["Managers are responsible for ensuring that productivity and communication remain consistent.","Quản lý chịu trách nhiệm đảm bảo năng suất và giao tiếp được duy trì ổn định."]],"vocab":["remotely = từ xa","provided that = với điều kiện là","arrangement = sự sắp xếp","in advance = trước","productivity = năng suất"]}', 15, 'published'),
  ('reading', 'office-chairs-ad', 'medium', NULL, 'Advertisement - Office Chairs', 'Chủ đề: quảng cáo ghế văn phòng.', '{"id":"office-chairs-ad","level":"medium","title":"Advertisement - Office Chairs","description":"Chủ đề: quảng cáo ghế văn phòng.","lines":[["ErgoPro Office Chairs","Ghế văn phòng ErgoPro"],["Upgrade your workspace with ErgoPro''s newest ergonomic chair.","Nâng cấp không gian làm việc của bạn với mẫu ghế công thái học mới nhất của ErgoPro."],["Designed for long workdays, it features adjustable armrests, breathable fabric, and enhanced lower-back support.","Được thiết kế cho những ngày làm việc dài, ghế có tay vịn điều chỉnh được, vải thoáng khí và hỗ trợ lưng dưới cải tiến."],["Corporate discounts are available for orders of ten or more units.","Ưu đãi doanh nghiệp áp dụng cho đơn hàng từ mười chiếc trở lên."],["Visit our showroom this week for a free consultation.","Hãy ghé phòng trưng bày của chúng tôi trong tuần này để được tư vấn miễn phí."]],"vocab":["ergonomic = công thái học","adjustable = có thể điều chỉnh","breathable fabric = vải thoáng khí","enhanced support = hỗ trợ cải tiến","consultation = buổi tư vấn","orders of ten or more units = đơn hàng từ 10 chiếc trở lên"]}', 16, 'published'),
  ('reading', 'schedule-revision', 'medium', NULL, 'Announcement - Schedule Revision', 'Chủ đề: thông báo thay đổi lịch tàu.', '{"id":"schedule-revision","level":"medium","title":"Announcement - Schedule Revision","description":"Chủ đề: thông báo thay đổi lịch tàu.","lines":[["Attention Passengers","Kính gửi hành khách"],["Due to maintenance work on the eastbound rail line, several morning trains will operate on a revised schedule this weekend.","Do công tác bảo trì trên tuyến đường sắt hướng đông, một số chuyến tàu buổi sáng sẽ chạy theo lịch điều chỉnh vào cuối tuần này."],["Passengers traveling between Hillview and Eastport should allow an additional twenty minutes for their journey.","Hành khách đi giữa Hillview và Eastport nên dự trù thêm hai mươi phút cho hành trình."],["Updated timetables are available at all ticket counters and on the company website.","Lịch trình cập nhật có tại tất cả quầy vé và trên trang web của công ty."]],"vocab":["maintenance work = công tác bảo trì","revised schedule = lịch điều chỉnh","allow additional time = dự trù thêm thời gian","timetable = thời gian biểu","should allow an additional twenty minutes = nên dự trù thêm 20 phút"]}', 17, 'published'),
  ('reading', 'corporate-strategy', 'hard', NULL, 'Corporate Strategy', 'Chủ đề: chiến lược tái định vị doanh nghiệp.', '{"id":"corporate-strategy","level":"hard","title":"Corporate Strategy","description":"Chủ đề: chiến lược tái định vị doanh nghiệp.","lines":[["The company is not merely trying to expand; it is repositioning itself in a crowded market where customer loyalty can no longer be taken for granted.","Công ty không chỉ đơn thuần cố gắng mở rộng; họ đang tái định vị mình trong một thị trường đông đúc, nơi lòng trung thành của khách hàng không còn là điều có thể mặc nhiên có được."],["By streamlining internal workflows, investing in data-driven decision-making, and sharpening its brand message, the firm hopes to move from short-term growth to sustainable relevance.","Bằng cách tinh gọn quy trình nội bộ, đầu tư vào việc ra quyết định dựa trên dữ liệu và làm sắc nét thông điệp thương hiệu, công ty hy vọng chuyển từ tăng trưởng ngắn hạn sang sự phù hợp bền vững."]],"vocab":["reposition itself = tái định vị","crowded market = thị trường đông đúc","taken for granted = được xem là hiển nhiên","streamlining workflows = tinh gọn quy trình","data-driven decision-making = ra quyết định dựa trên dữ liệu","sustainable relevance = sự phù hợp bền vững"]}', 18, 'published'),
  ('reading', 'workplace-culture', 'hard', NULL, 'Workplace Culture', 'Chủ đề: văn hóa làm việc dựa trên niềm tin.', '{"id":"workplace-culture","level":"hard","title":"Workplace Culture","description":"Chủ đề: văn hóa làm việc dựa trên niềm tin.","lines":[["A productive workplace is rarely built on rigid rules alone.","Một nơi làm việc hiệu quả hiếm khi chỉ được xây dựng trên các quy định cứng nhắc."],["It depends on mutual trust, clear expectations, and the quiet confidence that employees can raise concerns without being dismissed.","Nó phụ thuộc vào sự tin tưởng lẫn nhau, kỳ vọng rõ ràng và niềm tin âm thầm rằng nhân viên có thể nêu mối lo mà không bị gạt bỏ."],["When managers listen before reacting, small problems are often resolved before they become expensive failures.","Khi quản lý lắng nghe trước khi phản ứng, các vấn đề nhỏ thường được giải quyết trước khi trở thành sai lầm tốn kém."]],"vocab":["rigid rules = quy định cứng nhắc","mutual trust = sự tin tưởng lẫn nhau","clear expectations = kỳ vọng rõ ràng","raise concerns = nêu mối lo","be dismissed = bị gạt bỏ","listen before reacting = lắng nghe trước khi phản ứng"]}', 19, 'published'),
  ('reading', 'customer-experience', 'hard', NULL, 'Customer Experience', 'Chủ đề: trải nghiệm khách hàng và danh tiếng thương hiệu.', '{"id":"customer-experience","level":"hard","title":"Customer Experience","description":"Chủ đề: trải nghiệm khách hàng và danh tiếng thương hiệu.","lines":[["Customers do not always remember the technical details of a product, but they remember how effortless the experience felt.","Khách hàng không phải lúc nào cũng nhớ các chi tiết kỹ thuật của sản phẩm, nhưng họ nhớ trải nghiệm đó dễ dàng đến mức nào."],["A delayed response, a confusing return policy, or a careless handoff between departments can quietly damage a brand''s reputation.","Một phản hồi chậm, chính sách đổi trả khó hiểu hoặc sự bàn giao cẩu thả giữa các bộ phận có thể âm thầm làm tổn hại danh tiếng thương hiệu."],["In competitive industries, convenience is no longer a bonus; it is the baseline.","Trong các ngành cạnh tranh, sự tiện lợi không còn là điểm cộng; nó là tiêu chuẩn tối thiểu."]],"vocab":["effortless experience = trải nghiệm dễ dàng","delayed response = phản hồi chậm","return policy = chính sách đổi trả","careless handoff = bàn giao cẩu thả","damage a brand''s reputation = làm tổn hại danh tiếng thương hiệu","baseline = tiêu chuẩn tối thiểu"]}', 20, 'published'),
  ('reading', 'business-travel', 'hard', NULL, 'Business Travel', 'Chủ đề: đi công tác như một khoản đầu tư có cân nhắc.', '{"id":"business-travel","level":"hard","title":"Business Travel","description":"Chủ đề: đi công tác như một khoản đầu tư có cân nhắc.","lines":[["Business travel has changed from a routine obligation into a carefully weighed investment.","Đi công tác đã thay đổi từ một nghĩa vụ thường lệ thành một khoản đầu tư được cân nhắc kỹ."],["Companies now ask whether a trip will genuinely strengthen a partnership, accelerate a deal, or solve a problem that cannot be handled remotely.","Các công ty giờ đây đặt câu hỏi liệu chuyến đi có thật sự củng cố quan hệ đối tác, thúc đẩy một thương vụ hoặc giải quyết vấn đề không thể xử lý từ xa hay không."],["The best trips are no longer the longest ones, but the ones with a clear purpose and measurable value.","Những chuyến đi tốt nhất không còn là những chuyến dài nhất, mà là những chuyến có mục đích rõ ràng và giá trị đo lường được."]],"vocab":["routine obligation = nghĩa vụ thường lệ","carefully weighed investment = khoản đầu tư được cân nhắc kỹ","strengthen a partnership = củng cố quan hệ đối tác","accelerate a deal = thúc đẩy thương vụ","measurable value = giá trị đo lường được"]}', 21, 'published'),
  ('reading', 'leadership', 'hard', NULL, 'Leadership', 'Chủ đề: lãnh đạo bằng định hướng và sự bình tĩnh.', '{"id":"leadership","level":"hard","title":"Leadership","description":"Chủ đề: lãnh đạo bằng định hướng và sự bình tĩnh.","lines":[["Strong leadership is less about having the loudest voice in the room and more about setting a tone that others can trust.","Lãnh đạo mạnh mẽ không hẳn là có tiếng nói lớn nhất trong phòng, mà đúng hơn là tạo ra một phong thái khiến người khác tin tưởng."],["A good leader clarifies priorities, absorbs pressure without spreading panic, and gives people enough direction to move quickly without feeling micromanaged.","Một lãnh đạo tốt làm rõ ưu tiên, hấp thụ áp lực mà không lan truyền hoảng loạn, và đưa ra đủ định hướng để mọi người hành động nhanh mà không cảm thấy bị quản lý vi mô."]],"vocab":["set a tone = tạo phong thái/định hướng","clarify priorities = làm rõ ưu tiên","absorb pressure = chịu/hấp thụ áp lực","spreading panic = lan truyền hoảng loạn","micromanaged = bị quản lý quá chi tiết","less about... and more about... = không hẳn là..., mà đúng hơn là..."]}', 22, 'published'),
  ('listening', 'coffee-shop', 'B1', 'food-restaurant', 'Coffee Shop Secret', 'Bạn bước vào quán cà phê ở New York. Nhân viên hỏi rất nhanh, phía sau có tiếng máy pha cà phê.', '{"id":"coffee-shop","title":"Coffee Shop Secret","label":"Session 1","icon":"ti-cup","tone":"warm","goal":"food-restaurant","accent":"Indian","noise":"Coffee shop","level":"B1","badge":"Cafe Listener","baseScore":72,"opening":"Bạn bước vào quán cà phê ở New York. Nhân viên hỏi rất nhanh, phía sau có tiếng máy pha cà phê.","story":"Bạn là khách hàng. Hãy nghe nhân viên phục vụ hỏi và chọn câu phản hồi phù hợp trước khi xem transcript.","role":"Khách hàng đang gọi món","target":"Hiểu câu hỏi gọi món ở tốc độ tự nhiên","transcript":"Are you ready to order, or do you need a few more minutes?","nativeLine":"Are ya ready t''order, or d''ya need a few more minutes?","connectedSpeech":"Are you -> Are ya / or do you -> or d''ya / to order -> t''order","hardPart":"Are you ready to order, or do you","questionTitle":"Nhân viên đang hỏi bạn điều gì?","context":"Bạn cần phản hồi như một khách hàng trong quán.","options":[{"key":"A","text":"I need a few more minutes.","correct":true},{"key":"B","text":"Yes, I am food.","correct":false},{"key":"C","text":"I already paid yesterday.","correct":false}],"keywords":["ready","order","few","minutes"],"gapParts":["Are you ",{"answer":"ready"}," to order, or do you need a few more ",{"answer":"minutes"},"?"],"phrases":["Are you ready","to order","or do you need","a few more minutes"],"whyHard":["\\"Are you\\" thường nối thành \\"Are ya\\", nghe giống một cụm rất ngắn.","\\"to order\\" bị lướt nhanh thành \\"t''order\\", người học dễ bỏ mất từ \\"to\\".","Câu có hai lựa chọn nên trọng âm rơi vào \\"ready\\", \\"order\\", \\"few\\", \\"minutes\\"."],"missReason":"Nếu bạn chọn sai, khả năng cao bạn nghe được từ \\"order\\" nhưng bỏ lỡ cấu trúc câu hỏi hai lựa chọn.","mistakes":["connected","reduced","fast"]}', 1, 'published'),
  ('listening', 'airport', 'B1+', 'travel-directions', 'Airport Panic', 'Bạn vừa đáp xuống sân bay ở New York. Nhân viên hỏi một câu rất nhanh khi bạn đang tìm cổng nối chuyến.', '{"id":"airport","title":"Airport Panic","label":"Session 2","icon":"ti-location-arrow","tone":"green","goal":"travel-directions","accent":"Irish","noise":"Airport announcement","level":"B1+","badge":"Airport Master","baseScore":74,"opening":"Bạn vừa đáp xuống sân bay ở New York. Nhân viên hỏi một câu rất nhanh khi bạn đang tìm cổng nối chuyến.","story":"Bạn là hành khách. Hãy nghe thông báo và chọn đúng việc cần làm tiếp theo.","role":"Hành khách nối chuyến","target":"Bắt thông tin cổng, thời gian và hướng di chuyển","transcript":"Your connecting flight leaves from gate twenty-four in fifteen minutes.","nativeLine":"Yer connecting flight leaves from gate twenny-four in fifteen minutes.","connectedSpeech":"Your -> Yer / twenty-four -> twenny-four / fifteen nhấn mạnh âm cuối","hardPart":"gate twenty-four in fifteen minutes","questionTitle":"Bạn cần chú ý thông tin nào?","context":"Chọn phản hồi cho thấy bạn hiểu thông báo sân bay.","options":[{"key":"A","text":"I should go to gate twenty-four now.","correct":true},{"key":"B","text":"I have twenty-four minutes to buy coffee.","correct":false},{"key":"C","text":"My flight leaves tomorrow morning.","correct":false}],"keywords":["connecting","gate","twenty-four","fifteen"],"gapParts":["Your connecting flight leaves from gate ",{"answer":"twenty-four"}," in ",{"answer":"fifteen"}," minutes."],"phrases":["Your connecting flight","leaves from gate twenty-four","in fifteen minutes"],"whyHard":["\\"twenty-four\\" có âm /t/ giữa từ thường bị nói nhẹ.","\\"fifteen\\" nhấn ở âm cuối, dễ nhầm với \\"fifty\\" nếu không nghe trọng âm.","Tiếng thông báo sân bay làm người học bỏ lỡ số và thời gian."],"missReason":"Bạn dễ nhầm fifteen và fifty. Hãy nghe trọng âm: fifTEEN nhấn cuối, FIFty nhấn đầu.","mistakes":["numbers","ending","noise"]}', 2, 'published'),
  ('listening', 'office-call', 'B2', 'work-career', 'Office Voicemail', 'Sếp để lại voicemail ngắn trước cuộc họp. Bạn cần ghi đúng giờ và việc cần chuẩn bị.', '{"id":"office-call","title":"Office Voicemail","label":"Session 3","icon":"ti-briefcase","tone":"green","goal":"work-career","accent":"Irish","noise":"Phone call","level":"B2","badge":"Meeting Decoder","baseScore":76,"opening":"Sếp để lại voicemail ngắn trước cuộc họp. Bạn cần ghi đúng giờ và việc cần chuẩn bị.","story":"Bạn là trợ lý. Hãy nghe voicemail và chọn hành động chính xác.","role":"Trợ lý văn phòng","target":"Ghi lại việc cần làm từ voicemail","transcript":"Could you move the client meeting to half past three and send the updated agenda?","nativeLine":"Couldja move the client meeting t''half past three ''n send the updated agenda?","connectedSpeech":"Could you -> Couldja / to half -> t''half / and -> ''n","hardPart":"move the client meeting to half past three","questionTitle":"Bạn phải làm gì sau voicemail?","context":"Chọn hành động đúng nhất trong môi trường công sở.","options":[{"key":"A","text":"Move the meeting to 3:30 and send the new agenda.","correct":true},{"key":"B","text":"Cancel the meeting and call the client tomorrow.","correct":false},{"key":"C","text":"Send the old agenda before 3:00.","correct":false}],"keywords":["move","client meeting","half past three","agenda"],"gapParts":["Could you move the client meeting to ",{"answer":"half past three"}," and send the updated ",{"answer":"agenda"},"?"],"phrases":["Could you move","the client meeting","to half past three","send the updated agenda"],"whyHard":["\\"Could you\\" thường biến thành \\"Couldja\\" khi nói nhanh.","\\"half past three\\" là cụm thời gian; nếu bỏ một từ sẽ hiểu sai lịch.","Giọng điện thoại làm âm cuối của \\"updated\\" và \\"agenda\\" mờ hơn."],"missReason":"Nếu bạn nghe thiếu giờ hẹn, hãy loop riêng cụm \\"half past three\\" và chú ý nhịp rơi vào \\"three\\".","mistakes":["connected","numbers","noise"]}', 3, 'published'),
  ('listening', 'movie-sarcasm', 'B2', 'hobbies-free-time', 'Movie Mode: Hidden Meaning', 'Hai nhân vật đang cãi nhau nhẹ. Một câu nghe có vẻ tích cực, nhưng sắc thái lại không đơn giản.', '{"id":"movie-sarcasm","title":"Movie Mode: Hidden Meaning","label":"Session 4","icon":"ti-video-camera","tone":"danger","goal":"hobbies-free-time","accent":"Irish","noise":"Street background","level":"B2","badge":"Emotion Listener","baseScore":78,"opening":"Hai nhân vật đang cãi nhau nhẹ. Một câu nghe có vẻ tích cực, nhưng sắc thái lại không đơn giản.","story":"Bạn nghe một câu trong phim. Hãy đoán ý nghĩa thật sự phía sau câu nói.","role":"Người xem cần hiểu sắc thái","target":"Nghe cảm xúc, sarcasm và ý ngầm","transcript":"Yeah, that''s just great. Now we''re going to miss the train.","nativeLine":"Yeah, that''s jus'' great. Now we''re gonna miss the train.","connectedSpeech":"just -> jus'' / going to -> gonna / that''s just great có thể là mỉa mai","hardPart":"that''s just great","questionTitle":"Người nói thật sự đang cảm thấy gì?","context":"Đừng chỉ nghe từ vựng; hãy nghe ngữ điệu.","options":[{"key":"A","text":"Họ đang khó chịu và mỉa mai.","correct":true},{"key":"B","text":"Họ rất vui vì kế hoạch tốt hơn.","correct":false},{"key":"C","text":"Họ đang gọi món ở nhà hàng.","correct":false}],"keywords":["yeah","great","miss","train"],"gapParts":["Yeah, that''s just ",{"answer":"great"},". Now we''re going to miss the ",{"answer":"train"},"."],"phrases":["Yeah, that''s just great","Now we''re going to","miss the train"],"whyHard":["\\"great\\" không luôn mang nghĩa tích cực; ngữ điệu xuống và ngữ cảnh tạo sắc thái mỉa mai.","\\"going to\\" trong hội thoại thường thành \\"gonna\\".","Cụm \\"miss the train\\" cho biết tình huống đang xấu đi."],"missReason":"Bạn có thể hiểu từng từ nhưng bỏ lỡ cảm xúc. Hãy nghe pitch và ngữ cảnh sau câu.","mistakes":["emotion","reduced","fast"]}', 4, 'published'),
  ('listening', 'university', 'B2', 'study-school', 'University Class', 'Giảng viên nói nhanh ở cuối lớp. Bạn cần biết deadline bài essay trước khi mọi người rời phòng.', '{"id":"university","title":"University Class","label":"Session 5","icon":"ti-blackboard","tone":"green","goal":"study-school","accent":"Irish","noise":"Classroom","level":"B2","badge":"Lecture Catcher","baseScore":75,"opening":"Giảng viên nói nhanh ở cuối lớp. Bạn cần biết deadline bài essay trước khi mọi người rời phòng.","story":"Bạn là sinh viên. Hãy nghe giảng viên nhắc deadline và yêu cầu nộp bài.","role":"Sinh viên trong lớp đại học","target":"Bắt deadline và yêu cầu học thuật","transcript":"The essay is due next Friday, but you can submit a draft by Monday.","nativeLine":"The essay''s due nex'' Friday, but you can submit a draft by Monday.","connectedSpeech":"is due -> ''s due / next Friday -> nex'' Friday / can có âm yếu","hardPart":"due next Friday","questionTitle":"Deadline chính thức là khi nào?","context":"Chọn câu trả lời đúng về deadline.","options":[{"key":"A","text":"The final essay is due next Friday.","correct":true},{"key":"B","text":"The final essay is due this Monday.","correct":false},{"key":"C","text":"There is no draft before the deadline.","correct":false}],"keywords":["essay","due","next Friday","draft"],"gapParts":["The essay is due ",{"answer":"next Friday"},", but you can submit a ",{"answer":"draft"}," by Monday."],"phrases":["The essay is due","next Friday","submit a draft","by Monday"],"whyHard":["\\"next\\" mất âm /t/ khi đứng trước \\"Friday\\".","Câu có hai mốc thời gian nên người học dễ lấy nhầm Monday làm deadline chính.","\\"can\\" thường là âm yếu, không được nhấn mạnh."],"missReason":"Nếu bạn nhầm Monday là deadline chính, hãy phân biệt final deadline và draft deadline.","mistakes":["ending","numbers","accent"]}', 5, 'published'),
  ('listening', 'emergency', 'B2+', 'health-doctor', 'Emergency Call', 'Bạn nghe một cuộc gọi khẩn cấp ngoài đường. Thông tin ngắn, nhanh và có tiếng xe phía sau.', '{"id":"emergency","title":"Emergency Call","label":"Session 6","icon":"ti-support","tone":"danger","goal":"health-doctor","accent":"Irish","noise":"Street noise","level":"B2+","badge":"Crisis Listener","baseScore":80,"opening":"Bạn nghe một cuộc gọi khẩn cấp ngoài đường. Thông tin ngắn, nhanh và có tiếng xe phía sau.","story":"Bạn cần hiểu địa điểm và tình trạng để phản hồi đúng.","role":"Người hỗ trợ trong tình huống khẩn cấp","target":"Bắt thông tin quan trọng trong môi trường ồn","transcript":"I need an ambulance near the corner of Fifth and Main right away.","nativeLine":"I need an ambulance near the corner''a Fifth ''n Main right away.","connectedSpeech":"corner of -> corner''a / and -> ''n / right away nối nhanh","hardPart":"corner of Fifth and Main","questionTitle":"Xe cứu thương cần đến đâu?","context":"Chọn địa điểm chính xác.","options":[{"key":"A","text":"Near the corner of Fifth and Main.","correct":true},{"key":"B","text":"At the fifth main ambulance station.","correct":false},{"key":"C","text":"Near the airport gate.","correct":false}],"keywords":["ambulance","corner","Fifth","Main"],"gapParts":["I need an ambulance near the corner of ",{"answer":"Fifth"}," and ",{"answer":"Main"}," right away."],"phrases":["I need an ambulance","near the corner","of Fifth and Main","right away"],"whyHard":["Tên đường thường là thông tin quan trọng nhất nhưng bị tiếng nền che.","\\"of\\" và \\"and\\" đều là âm yếu, dễ biến mất trong tốc độ thật.","\\"right away\\" báo mức độ khẩn cấp, thường được nói rất nhanh."],"missReason":"Bạn cần ưu tiên nghe danh từ riêng trong môi trường ồn: Fifth, Main, ambulance.","mistakes":["noise","connected","fast"]}', 6, 'published'),
  ('listening', 'hotel-checkin', 'B1', 'travel-directions', 'Hotel Check-in Problem', 'Bạn đến khách sạn sau chuyến bay dài. Lễ tân nói nhanh về phòng và tiền đặt cọc.', '{"id":"hotel-checkin","title":"Hotel Check-in Problem","icon":"ti-home","tone":"warm","goal":"travel-directions","accent":"American","noise":"Hotel lobby","level":"B1","badge":"Hotel Listener","baseScore":73,"opening":"Bạn đến khách sạn sau chuyến bay dài. Lễ tân nói nhanh về phòng và tiền đặt cọc.","story":"Bạn là khách nhận phòng. Hãy nghe lễ tân và chọn phản hồi đúng.","role":"Khách nhận phòng","target":"Hiểu yêu cầu check-in và deposit","transcript":"Your room is ready, but I need a card for the security deposit.","nativeLine":"Your room''s ready, but I need a card for the security deposit.","connectedSpeech":"room is -> room''s / need a -> needa / security deposit là cụm thông tin chính","hardPart":"a card for the security deposit","questionTitle":"Lễ tân cần bạn đưa gì?","context":"Chọn phản hồi phù hợp khi nhận phòng.","correct":"Sure, here is my card.","distractors":["I want to deposit my luggage.","The room is not security."],"keywords":["room","ready","card","deposit"],"gapParts":["Your room is ",{"answer":"ready"},", but I need a card for the security ",{"answer":"deposit"},"."],"phrases":["Your room is ready","I need a card","for the security deposit"],"whyHard":["\\"room is\\" nối thành \\"room''s\\".","\\"need a\\" thường nghe như \\"needa\\".","Deposit là từ khóa tài chính dễ bị lướt qua trong lobby ồn."],"missReason":"Nếu bạn bỏ lỡ deposit, hãy nghe danh từ sau giới từ \\"for\\" vì đó thường là yêu cầu chính.","mistakes":["connected","noise","reduced"],"label":"Session 7","options":[{"key":"A","text":"Sure, here is my card.","correct":true},{"key":"B","text":"I want to deposit my luggage.","correct":false},{"key":"C","text":"The room is not security.","correct":false}]}', 7, 'published'),
  ('listening', 'taxi-route', 'B1', 'travel-directions', 'Taxi Route Change', 'Bạn đang trên taxi. Tài xế hỏi có muốn đi đường cao tốc để tránh kẹt xe không.', '{"id":"taxi-route","title":"Taxi Route Change","icon":"ti-car","tone":"green","goal":"travel-directions","accent":"Australian","noise":"Traffic","level":"B1","badge":"Route Catcher","baseScore":72,"opening":"Bạn đang trên taxi. Tài xế hỏi có muốn đi đường cao tốc để tránh kẹt xe không.","story":"Bạn là khách đi taxi. Hãy nghe tài xế và chọn câu trả lời đúng.","role":"Khách đi taxi","target":"Nghe hướng đi và lựa chọn tuyến đường","transcript":"Do you want me to take the highway, or should I avoid the toll?","nativeLine":"D''ya want me to take the highway, or should I avoid the toll?","connectedSpeech":"Do you -> D''ya / want me to -> wanna me t'' / should I -> shoulda-like khi nói nhanh","hardPart":"take the highway, or should I avoid the toll","questionTitle":"Tài xế đang hỏi gì?","context":"Chọn phản hồi đúng về tuyến đường.","correct":"Please take the highway.","distractors":["I want to buy a highway.","The toll is my hotel."],"keywords":["highway","avoid","toll","take"],"gapParts":["Do you want me to take the ",{"answer":"highway"},", or should I avoid the ",{"answer":"toll"},"?"],"phrases":["Do you want me to","take the highway","avoid the toll"],"whyHard":["\\"Do you\\" bị rút thành \\"D''ya\\".","Câu có hai lựa chọn nên dễ nghe sót vế sau.","Toll là từ ngắn, dễ bị tiếng giao thông che."],"missReason":"Bạn cần bắt hai từ khóa đối lập: highway và toll.","mistakes":["connected","noise","fast"],"label":"Session 8","options":[{"key":"A","text":"Please take the highway.","correct":true},{"key":"B","text":"I want to buy a highway.","correct":false},{"key":"C","text":"The toll is my hotel.","correct":false}]}', 8, 'published'),
  ('listening', 'lost-luggage', 'B1+', 'travel-directions', 'Lost Luggage Desk', 'Vali của bạn chưa ra băng chuyền. Nhân viên hỏi mô tả vali rất nhanh.', '{"id":"lost-luggage","title":"Lost Luggage Desk","icon":"ti-bag","tone":"danger","goal":"travel-directions","accent":"British","noise":"Airport desk","level":"B1+","badge":"Luggage Solver","baseScore":75,"opening":"Vali của bạn chưa ra băng chuyền. Nhân viên hỏi mô tả vali rất nhanh.","story":"Bạn ở quầy hành lý thất lạc. Hãy nghe câu hỏi và chọn câu trả lời đúng.","role":"Hành khách mất hành lý","target":"Hiểu yêu cầu mô tả đồ vật","transcript":"Could you describe the suitcase and tell me where you last saw it?","nativeLine":"Couldja describe the suitcase and tell me where ya last saw it?","connectedSpeech":"Could you -> Couldja / where you -> where ya / last saw it nối âm /t/ sang /s/","hardPart":"where you last saw it","questionTitle":"Nhân viên muốn biết điều gì?","context":"Chọn câu trả lời cho quầy lost luggage.","correct":"It is a black suitcase, and I last saw it at check-in.","distractors":["I saw the airport tomorrow.","My suitcase can describe me."],"keywords":["describe","suitcase","where","last"],"gapParts":["Could you describe the ",{"answer":"suitcase"}," and tell me where you last ",{"answer":"saw"}," it?"],"phrases":["Could you describe","the suitcase","where you last saw it"],"whyHard":["\\"Could you\\" biến thành \\"Couldja\\".","Cụm \\"last saw it\\" có nối âm nhanh.","Có hai yêu cầu trong một câu: describe và where."],"missReason":"Nếu bạn chỉ nghe được suitcase, hãy kiểm tra xem câu còn hỏi thêm where/when không.","mistakes":["connected","ending","fast"],"label":"Session 9","options":[{"key":"A","text":"It is a black suitcase, and I last saw it at check-in.","correct":true},{"key":"B","text":"I saw the airport tomorrow.","correct":false},{"key":"C","text":"My suitcase can describe me.","correct":false}]}', 9, 'published'),
  ('listening', 'standup-update', 'B1+', 'work-career', 'Daily Stand-up Update', 'Cuộc họp stand-up bắt đầu. Đồng nghiệp nói nhanh về block và deadline.', '{"id":"standup-update","title":"Daily Stand-up Update","icon":"ti-calendar","tone":"green","goal":"work-career","accent":"Indian","noise":"Video call","level":"B1+","badge":"Stand-up Ready","baseScore":74,"opening":"Cuộc họp stand-up bắt đầu. Đồng nghiệp nói nhanh về block và deadline.","story":"Bạn là thành viên team. Hãy nghe update và chọn việc cần làm tiếp theo.","role":"Thành viên dự án","target":"Bắt task, blocker và deadline","transcript":"I''m blocked on the login bug, but I can send the report by noon.","nativeLine":"I''m blocked on the login bug, but I can send the report by noon.","connectedSpeech":"blocked on nối /t/ nhẹ / can là âm yếu / by noon là deadline chính","hardPart":"send the report by noon","questionTitle":"Đồng nghiệp có thể làm gì trước buổi trưa?","context":"Chọn hành động đúng trong stand-up.","correct":"They can send the report by noon.","distractors":["They fixed the login bug already.","They need a lunch report."],"keywords":["blocked","login bug","report","noon"],"gapParts":["I''m blocked on the login ",{"answer":"bug"},", but I can send the report by ",{"answer":"noon"},"."],"phrases":["I''m blocked","on the login bug","send the report","by noon"],"whyHard":["\\"blocked on\\" có âm cuối /t/ rất nhẹ.","\\"can\\" không được nhấn mạnh nên dễ bỏ lỡ.","Noon là deadline ngắn, thường bị nghe lướt."],"missReason":"Đừng chỉ nghe vấn đề; câu sau \\"but\\" thường chứa việc vẫn làm được.","mistakes":["ending","fast","noise"],"label":"Session 10","options":[{"key":"A","text":"They can send the report by noon.","correct":true},{"key":"B","text":"They fixed the login bug already.","correct":false},{"key":"C","text":"They need a lunch report.","correct":false}]}', 10, 'published'),
  ('listening', 'job-interview', 'B2', 'self-introduction', 'Job Interview Follow-up', 'Người phỏng vấn hỏi câu follow-up về kinh nghiệm làm việc nhóm.', '{"id":"job-interview","title":"Job Interview Follow-up","icon":"ti-user","tone":"green","goal":"self-introduction","accent":"Indian","noise":"Quiet room","level":"B2","badge":"Interview Listener","baseScore":77,"opening":"Người phỏng vấn hỏi câu follow-up về kinh nghiệm làm việc nhóm.","story":"Bạn là ứng viên. Hãy nghe câu hỏi và chọn ý họ muốn biết.","role":"Ứng viên phỏng vấn","target":"Hiểu câu hỏi follow-up trong interview","transcript":"Could you walk me through a time when you had to handle a difficult teammate?","nativeLine":"Couldja walk me through a time when you hadta handle a difficult teammate?","connectedSpeech":"Could you -> Couldja / had to -> hadta / walk me through là cụm hỏi ví dụ","hardPart":"walk me through a time when","questionTitle":"Người phỏng vấn muốn bạn nói về điều gì?","context":"Chọn hướng trả lời phù hợp.","correct":"A past situation with a difficult teammate.","distractors":["A route to the office.","A teammate who walks too slowly."],"keywords":["walk me through","time","handle","teammate"],"gapParts":["Could you walk me through a ",{"answer":"time"}," when you had to handle a difficult ",{"answer":"teammate"},"?"],"phrases":["Could you walk me through","a time when","handle a difficult teammate"],"whyHard":["\\"walk me through\\" không có nghĩa đi bộ thật.","\\"had to\\" rút thành \\"hadta\\".","Câu dài nên cần bắt cụm hỏi chính."],"missReason":"Nếu nghe literal từng từ, bạn có thể hiểu sai idiom \\"walk me through\\".","mistakes":["reduced","fast","connected"],"label":"Session 11","options":[{"key":"A","text":"A past situation with a difficult teammate.","correct":true},{"key":"B","text":"A route to the office.","correct":false},{"key":"C","text":"A teammate who walks too slowly.","correct":false}]}', 11, 'published'),
  ('listening', 'sales-call', 'B2', 'shopping-prices', 'Sales Call Objection', 'Khách hàng nói nhanh vì đang bận. Bạn cần hiểu lý do họ chưa mua.', '{"id":"sales-call","title":"Sales Call Objection","icon":"ti-comments","tone":"warm","goal":"shopping-prices","accent":"Irish","noise":"Phone call","level":"B2","badge":"Client Decoder","baseScore":78,"opening":"Khách hàng nói nhanh vì đang bận. Bạn cần hiểu lý do họ chưa mua.","story":"Bạn là sales rep. Hãy nghe phản hồi của khách và chọn next step.","role":"Nhân viên sales","target":"Nghe objection và next action","transcript":"We''re interested, but the pricing is a little higher than we expected.","nativeLine":"We''re interested, but the pricing''s a little higher than we expected.","connectedSpeech":"pricing is -> pricing''s / a little -> alil / than we nối nhanh","hardPart":"a little higher than we expected","questionTitle":"Khách hàng đang lo ngại điều gì?","context":"Chọn phản hồi đúng cho cuộc gọi sales.","correct":"They are concerned about the price.","distractors":["They are not interested at all.","They expected a higher phone call."],"keywords":["interested","pricing","higher","expected"],"gapParts":["We''re interested, but the ",{"answer":"pricing"}," is a little higher than we ",{"answer":"expected"},"."],"phrases":["We''re interested","the pricing is","higher than expected"],"whyHard":["\\"but\\" báo hiệu phần quan trọng phía sau.","\\"pricing is\\" rút thành \\"pricing''s\\".","Cụm so sánh dài dễ bị mất nghĩa."],"missReason":"Nếu chỉ nghe interested, bạn sẽ bỏ lỡ objection sau \\"but\\".","mistakes":["reduced","connected","fast"],"label":"Session 12","options":[{"key":"A","text":"They are concerned about the price.","correct":true},{"key":"B","text":"They are not interested at all.","correct":false},{"key":"C","text":"They expected a higher phone call.","correct":false}]}', 12, 'published'),
  ('listening', 'it-support', 'B1+', 'tech-internet', 'IT Support Ticket', 'IT support gọi lại về lỗi đăng nhập. Accent khác khiến câu quen thuộc khó nghe hơn.', '{"id":"it-support","title":"IT Support Ticket","icon":"ti-settings","tone":"green","goal":"tech-internet","accent":"American","noise":"Office","level":"B1+","badge":"Support Listener","baseScore":74,"opening":"IT support gọi lại về lỗi đăng nhập. Accent khác khiến câu quen thuộc khó nghe hơn.","story":"Bạn là nhân viên cần hỗ trợ kỹ thuật. Hãy nghe và chọn việc cần làm.","role":"Người dùng nội bộ","target":"Nghe hướng dẫn kỹ thuật ngắn","transcript":"Please reset your password and try signing in again after five minutes.","nativeLine":"Please reset your password and try signing in again after five minutes.","connectedSpeech":"reset your nối /t/ sang /j/ / signing in nối /g/ nhẹ / five minutes là thời gian chờ","hardPart":"try signing in again after five minutes","questionTitle":"Bạn cần làm gì?","context":"Chọn bước xử lý ticket.","correct":"Reset the password and try again after five minutes.","distractors":["Sign out forever.","Wait five days before calling."],"keywords":["reset","password","signing in","five minutes"],"gapParts":["Please reset your ",{"answer":"password"}," and try signing in again after five ",{"answer":"minutes"},"."],"phrases":["reset your password","try signing in again","after five minutes"],"whyHard":["Accent khác làm nhịp câu khác với giọng Mỹ quen thuộc.","\\"signing in\\" là cụm phrasal verb.","Five minutes dễ nhầm thành five seconds nếu vội."],"missReason":"Bạn cần bắt động từ hành động: reset, try, wait.","mistakes":["accent","numbers","fast"],"label":"Session 13","options":[{"key":"A","text":"Reset the password and try again after five minutes.","correct":true},{"key":"B","text":"Sign out forever.","correct":false},{"key":"C","text":"Wait five days before calling.","correct":false}]}', 13, 'published'),
  ('listening', 'office-small-talk', 'A2+', 'self-introduction', 'Office Small Talk', 'Đồng nghiệp nói chuyện nhanh ở pantry. Câu rất đơn giản nhưng bị nuốt âm.', '{"id":"office-small-talk","title":"Office Small Talk","icon":"ti-comment-alt","tone":"warm","goal":"self-introduction","accent":"Irish","noise":"Office pantry","level":"A2+","badge":"Small Talk Ready","baseScore":70,"opening":"Đồng nghiệp nói chuyện nhanh ở pantry. Câu rất đơn giản nhưng bị nuốt âm.","story":"Bạn là nhân viên mới. Hãy nghe câu hỏi xã giao và chọn phản hồi tự nhiên.","role":"Nhân viên mới","target":"Phản xạ câu hỏi xã giao","transcript":"How''s your first week going so far?","nativeLine":"How''s your first week goin'' so far?","connectedSpeech":"How is -> How''s / going -> goin'' / so far là cụm hỏi trải nghiệm tới hiện tại","hardPart":"first week going so far","questionTitle":"Đồng nghiệp đang hỏi gì?","context":"Chọn câu trả lời tự nhiên.","correct":"It''s going well, thanks.","distractors":["I go by bus every week.","The first week is far away."],"keywords":["first week","going","so far"],"gapParts":["How''s your first ",{"answer":"week"}," going so ",{"answer":"far"},"?"],"phrases":["How''s your","first week going","so far"],"whyHard":["\\"How is\\" rút thành \\"How''s\\".","\\"going\\" mất /g/ cuối.","Câu hỏi xã giao cần hiểu ý, không dịch từng từ."],"missReason":"Bạn dễ nghe \\"going\\" thành di chuyển thật; ở đây là hỏi tình hình.","mistakes":["reduced","ending","connected"],"label":"Session 14","options":[{"key":"A","text":"It''s going well, thanks.","correct":true},{"key":"B","text":"I go by bus every week.","correct":false},{"key":"C","text":"The first week is far away.","correct":false}]}', 14, 'published'),
  ('listening', 'netflix-conversation', 'B1', 'hobbies-free-time', 'Netflix Conversation', 'Hai người đang chọn phim. Họ dùng câu rút gọn như trong hội thoại thật.', '{"id":"netflix-conversation","title":"Netflix Conversation","icon":"ti-video-clapper","tone":"warm","goal":"hobbies-free-time","accent":"American","noise":"Living room","level":"B1","badge":"Series Listener","baseScore":72,"opening":"Hai người đang chọn phim. Họ dùng câu rút gọn như trong hội thoại thật.","story":"Bạn nghe một đoạn casual conversation và chọn ý chính.","role":"Người nghe hội thoại đời thường","target":"Hiểu slang nhẹ và quyết định xem phim","transcript":"I don''t feel like watching another crime show tonight.","nativeLine":"I don'' feel like watchin'' another crime show tonight.","connectedSpeech":"don''t -> don'' / watching -> watchin'' / feel like = muốn làm gì","hardPart":"don''t feel like watching","questionTitle":"Người nói muốn gì?","context":"Chọn ý đúng của câu casual.","correct":"They do not want to watch another crime show.","distractors":["They feel like a criminal.","They want two crime shows."],"keywords":["don''t feel like","watching","another","crime show"],"gapParts":["I don''t feel like watching another ",{"answer":"crime"}," show ",{"answer":"tonight"},"."],"phrases":["I don''t feel like","watching another","crime show tonight"],"whyHard":["\\"feel like\\" là idiom, không dịch từng từ.","\\"don''t\\" mất âm /t/.","\\"watching\\" thường thành \\"watchin''\\"."],"missReason":"Nếu bạn hiểu từng từ riêng lẻ, cụm \\"feel like\\" sẽ gây nhầm.","mistakes":["reduced","ending","emotion"],"label":"Session 15","options":[{"key":"A","text":"They do not want to watch another crime show.","correct":true},{"key":"B","text":"They feel like a criminal.","correct":false},{"key":"C","text":"They want two crime shows.","correct":false}]}', 15, 'published'),
  ('listening', 'first-date', 'B2', 'family-friends', 'First Date Subtext', 'Trong buổi hẹn đầu, một câu nghe lịch sự nhưng thật ra là lời từ chối nhẹ.', '{"id":"first-date","title":"First Date Subtext","icon":"ti-heart","tone":"warm","goal":"family-friends","accent":"Indian","noise":"Restaurant","level":"B2","badge":"Subtext Listener","baseScore":77,"opening":"Trong buổi hẹn đầu, một câu nghe lịch sự nhưng thật ra là lời từ chối nhẹ.","story":"Bạn nghe sắc thái trong hội thoại hẹn hò và chọn ý ngầm.","role":"Người xem cần hiểu ý ngầm","target":"Nghe polite refusal","transcript":"I had a nice time, but I''m not really looking for anything serious right now.","nativeLine":"I had a nice time, but I''m not really lookin'' for anything serious right now.","connectedSpeech":"had a -> hadda / looking -> lookin'' / but báo hiệu ý chính phía sau","hardPart":"not really looking for anything serious","questionTitle":"Ý ngầm của người nói là gì?","context":"Chọn cách hiểu đúng sắc thái.","correct":"They are politely saying they do not want a serious relationship.","distractors":["They want to schedule a serious meeting.","They hated the whole evening."],"keywords":["nice time","not really","serious","right now"],"gapParts":["I had a nice ",{"answer":"time"},", but I''m not really looking for anything ",{"answer":"serious"}," right now."],"phrases":["I had a nice time","but I''m not really","looking for anything serious"],"whyHard":["\\"but\\" đổi hướng ý nghĩa của câu.","\\"not really\\" làm lời từ chối mềm hơn.","Sắc thái lịch sự dễ khiến người học hiểu quá tích cực."],"missReason":"Bạn cần nghe cụm giảm nhẹ như \\"not really\\" và \\"right now\\".","mistakes":["emotion","reduced","fast"],"label":"Session 16","options":[{"key":"A","text":"They are politely saying they do not want a serious relationship.","correct":true},{"key":"B","text":"They want to schedule a serious meeting.","correct":false},{"key":"C","text":"They hated the whole evening.","correct":false}]}', 16, 'published'),
  ('listening', 'party-gossip', 'B2', 'family-friends', 'Party Gossip', 'Bạn nghe lén ở một bữa tiệc. Hai người nói nhanh về một bí mật.', '{"id":"party-gossip","title":"Party Gossip","icon":"ti-comments-smiley","tone":"danger","goal":"family-friends","accent":"Canadian","noise":"Party","level":"B2","badge":"Gossip Decoder","baseScore":78,"opening":"Bạn nghe lén ở một bữa tiệc. Hai người nói nhanh về một bí mật.","story":"Bạn là người nghe lén. Hãy đoán thông tin bị giấu.","role":"Người nghe hội thoại trong tiệc","target":"Nghe trong tiếng ồn và đoán ngữ cảnh","transcript":"Don''t tell anyone, but I think she''s planning to quit next week.","nativeLine":"Don'' tell anyone, but I think she''s plannin'' to quit next week.","connectedSpeech":"Don''t -> Don'' / planning -> plannin'' / going to quit không xuất hiện nhưng ý định rõ","hardPart":"planning to quit next week","questionTitle":"Bí mật là gì?","context":"Chọn thông tin chính của đoạn gossip.","correct":"She may quit next week.","distractors":["She is planning a party next week.","They should tell everyone now."],"keywords":["don''t tell","planning","quit","next week"],"gapParts":["Don''t tell anyone, but I think she''s planning to ",{"answer":"quit"}," next ",{"answer":"week"},"."],"phrases":["Don''t tell anyone","I think she''s planning","to quit next week"],"whyHard":["Tiếng tiệc che các từ ngắn.","\\"planning\\" mất /g/ cuối.","\\"Don''t tell anyone\\" báo đây là thông tin bí mật."],"missReason":"Hãy ưu tiên động từ chính sau planning: quit.","mistakes":["noise","ending","fast"],"label":"Session 17","options":[{"key":"A","text":"She may quit next week.","correct":true},{"key":"B","text":"She is planning a party next week.","correct":false},{"key":"C","text":"They should tell everyone now.","correct":false}]}', 17, 'published'),
  ('listening', 'slang-joke', 'B2', 'hobbies-free-time', 'Slang Joke', 'Một nhân vật nói đùa bằng slang. Nếu dịch từng từ, câu sẽ rất khó hiểu.', '{"id":"slang-joke","title":"Slang Joke","icon":"ti-face-smile","tone":"warm","goal":"hobbies-free-time","accent":"British","noise":"Street","level":"B2","badge":"Slang Catcher","baseScore":76,"opening":"Một nhân vật nói đùa bằng slang. Nếu dịch từng từ, câu sẽ rất khó hiểu.","story":"Bạn nghe slang trong phim và chọn nghĩa tự nhiên.","role":"Người xem phim không phụ đề","target":"Hiểu slang và humor","transcript":"Relax, I''m just messing with you.","nativeLine":"Relax, I''m jus'' messin'' with ya.","connectedSpeech":"just -> jus'' / messing -> messin'' / with you -> with ya","hardPart":"just messing with you","questionTitle":"Người nói thật sự muốn nói gì?","context":"Chọn nghĩa tự nhiên của slang.","correct":"They are joking or teasing.","distractors":["They are cleaning a mess.","They are angry and serious."],"keywords":["relax","just","messing","with you"],"gapParts":["Relax, I''m just ",{"answer":"messing"}," with ",{"answer":"you"},"."],"phrases":["Relax","I''m just messing","with you"],"whyHard":["\\"messing with you\\" là slang nghĩa là trêu thôi.","\\"just\\" thường mất /t/.","\\"with you\\" thành \\"with ya\\"."],"missReason":"Nếu dịch \\"mess\\" là bừa bộn, bạn sẽ hiểu sai joke.","mistakes":["reduced","connected","emotion"],"label":"Session 18","options":[{"key":"A","text":"They are joking or teasing.","correct":true},{"key":"B","text":"They are cleaning a mess.","correct":false},{"key":"C","text":"They are angry and serious.","correct":false}]}', 18, 'published'),
  ('listening', 'detective-clue', 'B2+', 'news-society', 'Detective Clue', 'Trong phim trinh thám, một manh mối được nói rất nhỏ dưới tiếng mưa.', '{"id":"detective-clue","title":"Detective Clue","icon":"ti-search","tone":"danger","goal":"news-society","accent":"American","noise":"Rain","level":"B2+","badge":"Clue Hunter","baseScore":80,"opening":"Trong phim trinh thám, một manh mối được nói rất nhỏ dưới tiếng mưa.","story":"Bạn nghe một clue quan trọng và chọn kết luận đúng.","role":"Người xem phim trinh thám","target":"Bắt chi tiết then chốt trong tiếng nền","transcript":"He couldn''t have taken the train; the station was closed by then.","nativeLine":"He couldn''t''ve taken the train; the station was closed by then.","connectedSpeech":"couldn''t have -> couldn''t''ve / closed by then là mốc thời gian loại trừ","hardPart":"the station was closed by then","questionTitle":"Manh mối loại trừ điều gì?","context":"Chọn suy luận đúng.","correct":"He probably did not take the train.","distractors":["The station is open now.","He closed the train himself."],"keywords":["couldn''t have","train","station","closed"],"gapParts":["He couldn''t have taken the ",{"answer":"train"},"; the station was ",{"answer":"closed"}," by then."],"phrases":["He couldn''t have","taken the train","the station was closed"],"whyHard":["\\"couldn''t have\\" rút thành một cụm rất ngắn.","Tiếng mưa che âm cuối.","Dấu chấm phẩy trong nghĩa nói tạo quan hệ nguyên nhân."],"missReason":"Cấu trúc couldn''t have là suy luận quá khứ, không phải khả năng hiện tại.","mistakes":["reduced","noise","fast"],"label":"Session 19","options":[{"key":"A","text":"He probably did not take the train.","correct":true},{"key":"B","text":"The station is open now.","correct":false},{"key":"C","text":"He closed the train himself.","correct":false}]}', 19, 'published'),
  ('listening', 'weather-forecast', 'B1', 'weather-seasons', 'Weather Forecast Change', 'Bạn nghe bản tin thời tiết buổi sáng. Người dẫn nói nhanh về mưa lớn và việc đổi kế hoạch ngoài trời.', '{"id":"weather-forecast","title":"Weather Forecast Change","icon":"ti-announcement","tone":"green","goal":"weather-seasons","accent":"American","noise":"Radio forecast","level":"B1","badge":"Weather Planner","baseScore":73,"opening":"Bạn nghe bản tin thời tiết buổi sáng. Người dẫn nói nhanh về mưa lớn và việc đổi kế hoạch ngoài trời.","story":"Bạn cần quyết định có nên mang ô và chuyển hoạt động vào trong nhà hay không.","role":"Người nghe bản tin thời tiết","target":"Bắt nhiệt độ, mưa, gió và thay đổi kế hoạch","transcript":"Heavy rain is expected after three, so the outdoor concert may move indoors.","nativeLine":"Heavy rain''s expected after three, so the outdoor concert may move indoors.","connectedSpeech":"rain is -> rain''s / expected after nối âm / may move indoors là khả năng đổi địa điểm","hardPart":"the outdoor concert may move indoors","questionTitle":"Điều gì có thể xảy ra với concert?","context":"Chọn thông tin đúng từ bản tin thời tiết.","correct":"It may move indoors because of heavy rain.","distractors":["It will start before sunrise.","It was canceled because of snow."],"keywords":["heavy rain","after three","outdoor concert","indoors"],"gapParts":["Heavy rain is expected after ",{"answer":"three"},", so the outdoor concert may move ",{"answer":"indoors"},"."],"phrases":["Heavy rain is expected","after three","outdoor concert","move indoors"],"whyHard":["\\"rain is\\" rút thành \\"rain''s\\".","\\"may\\" chỉ khả năng, không phải chắc chắn.","Outdoor/indoors là cặp ý đối lập nên dễ nghe nhầm khi bản tin nhanh."],"missReason":"Khi nghe weather forecast, hãy bắt weather condition trước rồi mới nghe effect lên kế hoạch.","mistakes":["connected","fast","noise"],"label":"Session 20","options":[{"key":"A","text":"It may move indoors because of heavy rain.","correct":true},{"key":"B","text":"It will start before sunrise.","correct":false},{"key":"C","text":"It was canceled because of snow.","correct":false}]}', 20, 'published'),
  ('listening', 'ielts-lecture', 'B2', 'study-school', 'IELTS Mini Lecture', 'Một lecturer đưa ra nguyên nhân và kết quả trong câu dài kiểu IELTS.', '{"id":"ielts-lecture","title":"IELTS Mini Lecture","icon":"ti-blackboard","tone":"green","goal":"study-school","accent":"British","noise":"Lecture hall","level":"B2","badge":"Lecture Note Taker","baseScore":78,"opening":"Một lecturer đưa ra nguyên nhân và kết quả trong câu dài kiểu IELTS.","story":"Bạn nghe mini lecture và chọn ý chính.","role":"Thí sinh IELTS Listening","target":"Bắt cause-effect trong lecture","transcript":"The main reason for the decline is not temperature, but loss of habitat.","nativeLine":"The main reason for the decline isn''t temperature, but loss of habitat.","connectedSpeech":"is not -> isn''t / but báo ý đúng / loss of nối thành lossof","hardPart":"not temperature, but loss of habitat","questionTitle":"Nguyên nhân chính là gì?","context":"Chọn đáp án theo lecture.","correct":"Loss of habitat.","distractors":["Temperature only.","A decline in reason."],"keywords":["main reason","decline","not temperature","habitat"],"gapParts":["The main reason for the decline is not ",{"answer":"temperature"},", but loss of ",{"answer":"habitat"},"."],"phrases":["The main reason","not temperature","loss of habitat"],"whyHard":["Cấu trúc not A but B đặt đáp án sau but.","\\"loss of\\" nối âm rất nhanh.","Lecture có danh từ học thuật dài."],"missReason":"Nếu nghe temperature rồi chọn luôn, bạn sẽ mắc bẫy not A but B.","mistakes":["connected","fast","accent"],"label":"Session 21","options":[{"key":"A","text":"Loss of habitat.","correct":true},{"key":"B","text":"Temperature only.","correct":false},{"key":"C","text":"A decline in reason.","correct":false}]}', 21, 'published'),
  ('listening', 'toeic-direction', 'B1+', 'travel-directions', 'Map Direction Trap', 'Một câu chỉ đường có left/right và landmark nói rất nhanh.', '{"id":"toeic-direction","title":"Map Direction Trap","icon":"ti-map","tone":"warm","goal":"travel-directions","accent":"Indian","noise":"Station","level":"B1+","badge":"Map Listener","baseScore":75,"opening":"Một câu chỉ đường có left/right và landmark nói rất nhanh.","story":"Bạn nghe hướng dẫn và chọn điểm đến đúng.","role":"Người làm bài map labeling","target":"Nghe chỉ đường và landmark","transcript":"Go past the ticket office and turn left just before the stairs.","nativeLine":"Go past the ticket office and turn left jus'' before the stairs.","connectedSpeech":"past the nối /t/ nhẹ / just before -> jus'' before / turn left là hướng chính","hardPart":"turn left just before the stairs","questionTitle":"Bạn phải rẽ ở đâu?","context":"Chọn chỉ dẫn đúng.","correct":"Turn left before the stairs.","distractors":["Turn right after the stairs.","Go inside the ticket office."],"keywords":["ticket office","turn left","before","stairs"],"gapParts":["Go past the ticket office and turn ",{"answer":"left"}," just before the ",{"answer":"stairs"},"."],"phrases":["Go past the ticket office","turn left","before the stairs"],"whyHard":["Before/after là bẫy nghe thường gặp.","\\"just\\" mất /t/.","Tiếng station làm landmark khó nghe."],"missReason":"Hãy bắt thứ tự: past ticket office -> before stairs -> turn left.","mistakes":["ending","noise","fast"],"label":"Session 22","options":[{"key":"A","text":"Turn left before the stairs.","correct":true},{"key":"B","text":"Turn right after the stairs.","correct":false},{"key":"C","text":"Go inside the ticket office.","correct":false}]}', 22, 'published'),
  ('listening', 'number-trap', 'B1', 'tech-internet', 'Number Trap', 'Một số điện thoại được đọc qua đường dây hơi rè, có cặp thirteen/thirty.', '{"id":"number-trap","title":"Number Trap","icon":"ti-stats-up","tone":"danger","goal":"tech-internet","accent":"British","noise":"Phone line","level":"B1","badge":"Number Defender","baseScore":74,"opening":"Một số điện thoại được đọc qua đường dây hơi rè, có cặp thirteen/thirty.","story":"Bạn nghe số và chọn bản ghi đúng.","role":"Thí sinh nghe số","target":"Phân biệt teen/ty và dãy số","transcript":"Please call me back at three one zero, thirteen, forty-eight.","nativeLine":"Please call me back at three one oh, thirteen, forty-eight.","connectedSpeech":"zero thường đọc là oh / thirteen nhấn âm cuối / forty-eight nối nhẹ","hardPart":"three one zero, thirteen, forty-eight","questionTitle":"Dãy số nào đúng?","context":"Chọn số nghe được.","correct":"310-13-48.","distractors":["310-30-48.","301-13-58."],"keywords":["three one zero","thirteen","forty-eight"],"gapParts":["Please call me back at three one ",{"answer":"zero"},", thirteen, forty-",{"answer":"eight"},"."],"phrases":["call me back","three one zero","thirteen forty-eight"],"whyHard":["Zero có thể đọc là oh.","Thirteen nhấn cuối, thirty nhấn đầu.","Dãy số qua điện thoại không có ngữ cảnh hỗ trợ."],"missReason":"Khi nghe teen/ty, hãy chú ý trọng âm chứ không chỉ phụ âm.","mistakes":["numbers","noise","accent"],"label":"Session 23","options":[{"key":"A","text":"310-13-48.","correct":true},{"key":"B","text":"310-30-48.","correct":false},{"key":"C","text":"301-13-58.","correct":false}]}', 23, 'published'),
  ('listening', 'short-talk-sale', 'B1', 'shopping-prices', 'Store Promotion', 'Một thông báo khuyến mãi trong cửa hàng có điều kiện và thời hạn.', '{"id":"short-talk-sale","title":"Store Promotion","icon":"ti-shopping-cart","tone":"warm","goal":"shopping-prices","accent":"American","noise":"Store PA","level":"B1","badge":"Promo Listener","baseScore":73,"opening":"Một thông báo khuyến mãi trong cửa hàng có điều kiện và thời hạn.","story":"Bạn nghe short talk và chọn điều kiện khuyến mãi.","role":"Khách nghe thông báo","target":"Bắt điều kiện giảm giá","transcript":"Customers who spend over fifty pounds today will receive a free delivery voucher.","nativeLine":"Customers who spend over fifty pounds today''ll receive a free delivery voucher.","connectedSpeech":"today will -> today''ll / fifty pounds là ngưỡng tiền / free delivery voucher là quyền lợi","hardPart":"spend over fifty pounds today","questionTitle":"Điều kiện để nhận voucher là gì?","context":"Chọn điều kiện đúng.","correct":"Spend over fifty pounds today.","distractors":["Spend exactly fifteen pounds.","Receive delivery before buying."],"keywords":["spend","over fifty","today","voucher"],"gapParts":["Customers who spend over ",{"answer":"fifty"}," pounds today will receive a free delivery ",{"answer":"voucher"},"."],"phrases":["Customers who spend","over fifty pounds today","free delivery voucher"],"whyHard":["Fifty/fifteen là bẫy số.","\\"today will\\" nối thành \\"today''ll\\".","Thông báo PA có tiếng vang."],"missReason":"Trong promotion, hãy nghe condition trước reward.","mistakes":["numbers","connected","noise"],"label":"Session 24","options":[{"key":"A","text":"Spend over fifty pounds today.","correct":true},{"key":"B","text":"Spend exactly fifteen pounds.","correct":false},{"key":"C","text":"Receive delivery before buying.","correct":false}]}', 24, 'published'),
  ('listening', 'opinion-summary', 'B2', 'news-society', 'Opinion Summary', 'Một người đổi ý giữa câu bằng however. Đây là dạng bẫy ý kiến trong bài thi.', '{"id":"opinion-summary","title":"Opinion Summary","icon":"ti-thought","tone":"green","goal":"news-society","accent":"Indian","noise":"Class discussion","level":"B2","badge":"Opinion Catcher","baseScore":77,"opening":"Một người đổi ý giữa câu bằng however. Đây là dạng bẫy ý kiến trong bài thi.","story":"Bạn nghe ý kiến và chọn thái độ cuối cùng.","role":"Thí sinh nghe discussion","target":"Bắt opinion shift","transcript":"I liked the proposal at first; however, the budget seems unrealistic.","nativeLine":"I liked the proposal at first; however, the budget seems unrealistic.","connectedSpeech":"liked the nối âm / however đổi hướng ý kiến / budget seems nối /t s/","hardPart":"however, the budget seems unrealistic","questionTitle":"Thái độ cuối cùng là gì?","context":"Chọn ý đúng sau từ chuyển hướng.","correct":"They are concerned about the budget.","distractors":["They fully support the proposal.","They dislike every proposal."],"keywords":["liked","however","budget","unrealistic"],"gapParts":["I liked the proposal at first; however, the ",{"answer":"budget"}," seems ",{"answer":"unrealistic"},"."],"phrases":["liked the proposal","however","budget seems unrealistic"],"whyHard":["However báo ý sau mới quyết định đáp án.","\\"liked the\\" nối âm /d th/.","Unrealistic là từ dài dễ nghe thiếu âm đầu."],"missReason":"Đừng chọn ý đầu câu khi có however/but/yet.","mistakes":["connected","fast","emotion"],"label":"Session 25","options":[{"key":"A","text":"They are concerned about the budget.","correct":true},{"key":"B","text":"They fully support the proposal.","correct":false},{"key":"C","text":"They dislike every proposal.","correct":false}]}', 25, 'published'),
  ('listening', 'library-request', 'B1', 'study-school', 'Library Request', 'Thủ thư nói nhỏ về việc gia hạn sách và phí trễ hạn.', '{"id":"library-request","title":"Library Request","icon":"ti-book","tone":"green","goal":"study-school","accent":"Australian","noise":"Library desk","level":"B1","badge":"Library Ready","baseScore":72,"opening":"Thủ thư nói nhỏ về việc gia hạn sách và phí trễ hạn.","story":"Bạn là sinh viên ở thư viện. Hãy nghe và chọn hành động đúng.","role":"Sinh viên mượn sách","target":"Hiểu thủ tục thư viện","transcript":"You can renew the book online, but the late fee still has to be paid.","nativeLine":"You can renew the book online, but the late fee still hasta be paid.","connectedSpeech":"has to -> hasta / but báo thông tin giới hạn / late fee là phí chính","hardPart":"the late fee still has to be paid","questionTitle":"Bạn vẫn phải làm gì?","context":"Chọn thông tin đúng về thư viện.","correct":"Pay the late fee.","distractors":["Return the website online.","Renew the fee forever."],"keywords":["renew","online","late fee","paid"],"gapParts":["You can renew the book online, but the late ",{"answer":"fee"}," still has to be ",{"answer":"paid"},"."],"phrases":["renew the book online","but the late fee","has to be paid"],"whyHard":["Câu có but nên ý sau quan trọng.","\\"has to\\" thành \\"hasta\\".","Late fee dễ bị nghe thành late free."],"missReason":"Nếu nghe renew online mà bỏ qua but, bạn sẽ thiếu nghĩa chính.","mistakes":["reduced","connected","ending"],"label":"Session 26","options":[{"key":"A","text":"Pay the late fee.","correct":true},{"key":"B","text":"Return the website online.","correct":false},{"key":"C","text":"Renew the fee forever.","correct":false}]}', 26, 'published'),
  ('listening', 'group-project', 'B1+', 'study-school', 'Group Project Plan', 'Nhóm học ở quán cà phê trong campus. Một bạn chia task nhanh.', '{"id":"group-project","title":"Group Project Plan","icon":"ti-layout-grid2","tone":"warm","goal":"study-school","accent":"American","noise":"Campus cafe","level":"B1+","badge":"Project Partner","baseScore":73,"opening":"Nhóm học ở quán cà phê trong campus. Một bạn chia task nhanh.","story":"Bạn là thành viên nhóm. Hãy nghe task của mình.","role":"Sinh viên làm project","target":"Bắt phân công công việc","transcript":"Can you handle the slides while I work on the research summary?","nativeLine":"Can ya handle the slides while I work on the research summary?","connectedSpeech":"Can you -> Can ya / work on nối âm / research summary là cụm dài","hardPart":"handle the slides","questionTitle":"Bạn được giao làm gì?","context":"Chọn task đúng.","correct":"Prepare the slides.","distractors":["Write the research summary.","Handle the coffee cups."],"keywords":["handle","slides","research summary"],"gapParts":["Can you handle the ",{"answer":"slides"}," while I work on the research ",{"answer":"summary"},"?"],"phrases":["Can you handle","the slides","research summary"],"whyHard":["\\"Can you\\" nghe như \\"Can ya\\".","\\"while\\" chia hai vai trò khác nhau.","Summary là từ dài ở cuối câu dễ bị mờ."],"missReason":"Hãy xác định ai làm gì quanh từ while.","mistakes":["connected","fast","noise"],"label":"Session 27","options":[{"key":"A","text":"Prepare the slides.","correct":true},{"key":"B","text":"Write the research summary.","correct":false},{"key":"C","text":"Handle the coffee cups.","correct":false}]}', 27, 'published'),
  ('listening', 'office-hours', 'B2', 'study-school', 'Professor Office Hours', 'Giáo sư nói nhanh ngoài hành lang về giờ gặp và tài liệu cần mang.', '{"id":"office-hours","title":"Professor Office Hours","icon":"ti-time","tone":"green","goal":"study-school","accent":"Indian","noise":"Hallway","level":"B2","badge":"Office Hours Ready","baseScore":76,"opening":"Giáo sư nói nhanh ngoài hành lang về giờ gặp và tài liệu cần mang.","story":"Bạn là sinh viên muốn hỏi bài. Hãy nghe lịch hẹn.","role":"Sinh viên gặp giáo sư","target":"Bắt lịch hẹn và yêu cầu chuẩn bị","transcript":"Drop by my office after lunch, and bring your draft with comments.","nativeLine":"Drop by my office after lunch, and bring your draft with comments.","connectedSpeech":"drop by là phrasal verb / bring your nối /g j/ / draft with nối âm /t w/","hardPart":"bring your draft with comments","questionTitle":"Bạn cần mang gì?","context":"Chọn yêu cầu đúng.","correct":"Bring the draft with comments.","distractors":["Bring lunch to the office.","Drop the comments after class."],"keywords":["drop by","after lunch","draft","comments"],"gapParts":["Drop by my office after ",{"answer":"lunch"},", and bring your draft with ",{"answer":"comments"},"."],"phrases":["Drop by my office","after lunch","bring your draft"],"whyHard":["Drop by không phải thả đồ, mà là ghé qua.","\\"draft with\\" nối âm nhanh.","After lunch là thời điểm, không phải vật cần mang."],"missReason":"Câu có hai phần: thời gian đến và vật cần mang.","mistakes":["connected","reduced","fast"],"label":"Session 28","options":[{"key":"A","text":"Bring the draft with comments.","correct":true},{"key":"B","text":"Bring lunch to the office.","correct":false},{"key":"C","text":"Drop the comments after class.","correct":false}]}', 28, 'published'),
  ('listening', 'dorm-maintenance', 'B1+', 'daily-routine', 'Dorm Maintenance Call', 'Ký túc xá gọi về lịch sửa điều hòa. Accent và đường dây làm câu khó hơn.', '{"id":"dorm-maintenance","title":"Dorm Maintenance Call","icon":"ti-home","tone":"danger","goal":"daily-routine","accent":"Canadian","noise":"Phone call","level":"B1+","badge":"Dorm Solver","baseScore":74,"opening":"Ký túc xá gọi về lịch sửa điều hòa. Accent và đường dây làm câu khó hơn.","story":"Bạn là sinh viên ở dorm. Hãy nghe lịch sửa phòng.","role":"Sinh viên ở ký túc xá","target":"Nghe lịch bảo trì","transcript":"The technician will come between nine and eleven tomorrow morning.","nativeLine":"The technician''ll come between nine and eleven tomorrow morning.","connectedSpeech":"technician will -> technician''ll / between nine and eleven là khoảng thời gian","hardPart":"between nine and eleven tomorrow morning","questionTitle":"Kỹ thuật viên sẽ đến khi nào?","context":"Chọn khoảng thời gian đúng.","correct":"Between 9 and 11 tomorrow morning.","distractors":["At 9:11 tonight.","Between Monday and morning."],"keywords":["technician","between","nine","eleven"],"gapParts":["The technician will come between ",{"answer":"nine"}," and eleven tomorrow ",{"answer":"morning"},"."],"phrases":["The technician will come","between nine and eleven","tomorrow morning"],"whyHard":["Between báo khoảng thời gian, không phải một mốc.","Nine/eleven qua điện thoại dễ nhập nhầm.","Accent khác làm rhythm thay đổi."],"missReason":"Hãy nghe từ between để biết đây là time window.","mistakes":["numbers","accent","noise"],"label":"Session 29","options":[{"key":"A","text":"Between 9 and 11 tomorrow morning.","correct":true},{"key":"B","text":"At 9:11 tonight.","correct":false},{"key":"C","text":"Between Monday and morning.","correct":false}]}', 29, 'published'),
  ('listening', 'scholarship-call', 'B2', 'study-school', 'Scholarship Call', 'Văn phòng học bổng gọi nhắc deadline bổ sung giấy tờ.', '{"id":"scholarship-call","title":"Scholarship Call","icon":"ti-medall","tone":"warm","goal":"study-school","accent":"Canadian","noise":"Office phone","level":"B2","badge":"Scholarship Listener","baseScore":78,"opening":"Văn phòng học bổng gọi nhắc deadline bổ sung giấy tờ.","story":"Bạn là sinh viên nộp học bổng. Hãy nghe việc còn thiếu.","role":"Ứng viên học bổng","target":"Bắt deadline và tài liệu cần nộp","transcript":"We still need your recommendation letter before the deadline on Friday.","nativeLine":"We still need your recommendation letter before the deadline on Friday.","connectedSpeech":"need your nối /d j/ / recommendation letter là cụm dài / deadline on nối âm","hardPart":"recommendation letter before the deadline","questionTitle":"Bạn cần nộp gì?","context":"Chọn tài liệu còn thiếu.","correct":"A recommendation letter before Friday.","distractors":["A Friday letter before recommendation.","No documents are missing."],"keywords":["need","recommendation letter","deadline","Friday"],"gapParts":["We still need your recommendation ",{"answer":"letter"}," before the deadline on ",{"answer":"Friday"},"."],"phrases":["We still need","recommendation letter","before the deadline"],"whyHard":["Recommendation là từ dài dễ mất âm giữa.","Still need báo còn thiếu.","Friday nằm cuối câu nên dễ bị bỏ qua."],"missReason":"Trong cuộc gọi hành chính, still need thường báo action item.","mistakes":["fast","connected","ending"],"label":"Session 30","options":[{"key":"A","text":"A recommendation letter before Friday.","correct":true},{"key":"B","text":"A Friday letter before recommendation.","correct":false},{"key":"C","text":"No documents are missing.","correct":false}]}', 30, 'published'),
  ('listening', 'new-colleague-intro', 'A2+', 'self-introduction', 'New Colleague Intro', 'Bạn đang trong buổi orientation. Một nhân viên mới tự giới thiệu rất nhanh trước team.', '{"id":"new-colleague-intro","title":"New Colleague Intro","icon":"ti-id-badge","tone":"green","goal":"self-introduction","accent":"Canadian","noise":"Office orientation","level":"A2+","badge":"First Day Ready","baseScore":71,"opening":"Bạn đang trong buổi orientation. Một nhân viên mới tự giới thiệu rất nhanh trước team.","story":"Bạn là đồng nghiệp mới. Hãy nghe để biết người đó làm bộ phận nào và có điểm mạnh gì.","role":"Đồng nghiệp trong ngày đầu","target":"Bắt tên, vị trí, kinh nghiệm và điểm mạnh cá nhân","transcript":"Hi, I''m Maya, and I just joined the design team after two years in marketing.","nativeLine":"Hi, I''m Maya, ''n I just joined the design team after two years in marketing.","connectedSpeech":"and I -> ''n I / just joined -> jus'' joined / years in nối âm","hardPart":"joined the design team after two years","questionTitle":"Maya vừa vào team nào?","context":"Chọn thông tin đúng trong phần giới thiệu nhân viên mới.","correct":"She joined the design team.","distractors":["She left the design team.","She joined a travel group."],"keywords":["Maya","joined","design team","marketing"],"missReason":"Trong self-introduction, hãy bắt role mới trước rồi mới nghe kinh nghiệm cũ.","mistakes":["connected","fast","ending"],"label":"Session 31","options":[{"key":"A","text":"She joined the design team.","correct":true},{"key":"B","text":"She left the design team.","correct":false},{"key":"C","text":"She joined a travel group.","correct":false}],"gapParts":["Hi, I''m Maya, and I just joined the ",{"answer":"design team"}," after two years in ",{"answer":"marketing"},"."],"phrases":["Hi, I''m Maya, and","I just joined the","design team after two","years in marketing"],"whyHard":["and I -> ''n I / just joined -> jus'' joined / years in nối âm","\\"joined the design team after two years