  ('listening', 'economy-price-news', 'B2', 'news-society', 'Price News Brief', 'Bản tin đời sống nói giá thực phẩm tăng nhưng xăng giảm nhẹ.', '{"id":"economy-price-news","title":"Price News Brief","icon":"ti-money","tone":"warm","goal":"news-society","accent":"British","noise":"Radio news","level":"B2","badge":"Economy Catcher","baseScore":78,"opening":"Bản tin đời sống nói giá thực phẩm tăng nhưng xăng giảm nhẹ.","story":"Bạn cần nghe đối lập giữa hai chỉ số giá.","role":"Người nghe bản tin kinh tế đời sống","target":"Bắt economy, prices và contrast signal","transcript":"Food prices rose again this month, while fuel costs fell slightly.","nativeLine":"Food prices rose again this month, while fuel costs fell slightly.","connectedSpeech":"prices rose nối / while báo đối lập / fell slightly nối","hardPart":"while fuel costs fell slightly","questionTitle":"Điều gì giảm nhẹ?","context":"Chọn thông tin đối lập trong bản tin.","correct":"Fuel costs.","distractors":["Food prices.","The whole economy."],"keywords":["food prices","rose","fuel costs","fell slightly"],"missReason":"While báo hai xu hướng trái nhau; cần nghe cả hai vế.","mistakes":["connected","fast","emotion"],"label":"Session 74","options":[{"key":"A","text":"Fuel costs.","correct":true},{"key":"B","text":"Food prices.","correct":false},{"key":"C","text":"The whole economy.","correct":false}],"gapParts":["Food prices rose again this month, while ",{"answer":"fuel costs"}," ",{"answer":"fell slightly"},"."],"phrases":["Food prices rose again","this month, while fuel","costs fell slightly"],"whyHard":["prices rose nối / while báo đối lập / fell slightly nối","\\"while fuel costs fell slightly\\" là đoạn cần loop riêng vì chứa thông tin quyết định đáp án.","Hãy nghe từ khóa nội dung trước, rồi mới mở transcript để kiểm tra chi tiết."]}', 74, 'published'),
  ('listening', 'app-password-reset', 'B1', 'tech-internet', 'Password Reset', 'Nhân viên hỗ trợ hướng dẫn reset password và bật xác minh hai bước.', '{"id":"app-password-reset","title":"Password Reset","icon":"ti-lock","tone":"green","goal":"tech-internet","accent":"Irish","noise":"Support chat","level":"B1","badge":"Security Listener","baseScore":73,"opening":"Nhân viên hỗ trợ hướng dẫn reset password và bật xác minh hai bước.","story":"Bạn cần nghe bước tiếp theo để bảo mật tài khoản.","role":"Người dùng app","target":"Bắt password, account security và two-step verification","transcript":"Reset your password first, then turn on two-step verification in settings.","nativeLine":"Reset your password first, then turn on two-step verification in settings.","connectedSpeech":"reset your nối / turn on là phrasal verb / two-step verification là cụm dài","hardPart":"turn on two-step verification","questionTitle":"Sau khi reset password, cần làm gì?","context":"Chọn bước bảo mật tiếp theo.","correct":"Turn on two-step verification.","distractors":["Delete the account.","Upload a shopping receipt."],"keywords":["reset","password","turn on","two-step verification"],"missReason":"Then báo bước thứ hai trong quy trình.","mistakes":["connected","fast","reduced"],"label":"Session 75","options":[{"key":"A","text":"Turn on two-step verification.","correct":true},{"key":"B","text":"Delete the account.","correct":false},{"key":"C","text":"Upload a shopping receipt.","correct":false}],"gapParts":["Reset your password first, then ",{"answer":"turn on"}," ",{"answer":"two-step verification"}," in settings."],"phrases":["Reset your password first,","then turn on two-step","verification in settings"],"whyHard":["reset your nối / turn on là phrasal verb / two-step verification là cụm dài","\\"turn on two-step verification\\" là đoạn cần loop riêng vì chứa thông tin quyết định đáp án.","Hãy nghe từ khóa nội dung trước, rồi mới mở transcript để kiểm tra chi tiết."]}', 75, 'published'),
  ('listening', 'video-call-lag', 'B1+', 'tech-internet', 'Video Call Lag', 'Trong lớp online, giáo viên giải thích cách xử lý cuộc gọi bị lag.', '{"id":"video-call-lag","title":"Video Call Lag","icon":"ti-video-camera","tone":"danger","goal":"tech-internet","accent":"Indian","noise":"Video call","level":"B1+","badge":"Call Fixer","baseScore":74,"opening":"Trong lớp online, giáo viên giải thích cách xử lý cuộc gọi bị lag.","story":"Bạn cần nghe giải pháp kỹ thuật đơn giản.","role":"Học viên học online","target":"Bắt app issue, Internet connection và troubleshooting","transcript":"If the video keeps freezing, turn off your camera and rejoin the call.","nativeLine":"If the video keeps freezing, turn off your camera ''n rejoin the call.","connectedSpeech":"keeps freezing nối / turn off là phrasal verb / and rejoin -> ''n rejoin","hardPart":"turn off your camera and rejoin the call","questionTitle":"Người học nên làm gì nếu video bị đứng?","context":"Chọn cách xử lý đúng.","correct":"Turn off the camera and rejoin.","distractors":["Turn off the teacher.","Buy a new phone immediately."],"keywords":["video","freezing","camera","rejoin"],"missReason":"If nêu lỗi, các động từ sau đó là bước xử lý.","mistakes":["connected","noise","fast"],"label":"Session 76","options":[{"key":"A","text":"Turn off the camera and rejoin.","correct":true},{"key":"B","text":"Turn off the teacher.","correct":false},{"key":"C","text":"Buy a new phone immediately.","correct":false}],"gapParts":["If the video keeps freezing, turn off your ",{"answer":"camera"}," and ",{"answer":"rejoin"}," the call."],"phrases":["If the video keeps","freezing, turn off your","camera and rejoin the","call"],"whyHard":["keeps freezing nối / turn off là phrasal verb / and rejoin -> ''n rejoin","\\"turn off your camera and rejoin the call\\" là đoạn cần loop riêng vì chứa thông tin quyết định đáp án.","Hãy nghe từ khóa nội dung trước, rồi mới mở transcript để kiểm tra chi tiết."]}', 76, 'published'),
  ('listening', 'social-media-screen-time', 'B2', 'tech-internet', 'Social Media Screen Time', 'Podcast công nghệ nói về cách giảm thời gian dùng mạng xã hội.', '{"id":"social-media-screen-time","title":"Social Media Screen Time","icon":"ti-mobile","tone":"warm","goal":"tech-internet","accent":"Australian","noise":"Podcast","level":"B2","badge":"Digital Balance","baseScore":77,"opening":"Podcast công nghệ nói về cách giảm thời gian dùng mạng xã hội.","story":"Bạn cần nghe tính năng được khuyên bật.","role":"Người nghe podcast công nghệ","target":"Bắt social media, screen time và app settings","transcript":"Set a daily limit for social media apps instead of deleting them completely.","nativeLine":"Set a daily limit for social media apps instead''a deleting them completely.","connectedSpeech":"instead of -> instead''a / daily limit là cài đặt chính / deleting them nối","hardPart":"instead of deleting them completely","questionTitle":"Podcast khuyên làm gì?","context":"Chọn giải pháp cân bằng.","correct":"Set a daily limit for social media apps.","distractors":["Delete every app immediately.","Upload more videos."],"keywords":["daily limit","social media","instead of","deleting"],"missReason":"Instead of báo điều không làm; đáp án là set a daily limit.","mistakes":["reduced","accent","fast"],"label":"Session 77","options":[{"key":"A","text":"Set a daily limit for social media apps.","correct":true},{"key":"B","text":"Delete every app immediately.","correct":false},{"key":"C","text":"Upload more videos.","correct":false}],"gapParts":["Set a daily limit for social media apps ",{"answer":"instead of"}," ",{"answer":"deleting"}," them completely."],"phrases":["Set a daily limit","for social media apps","instead of deleting them","completely"],"whyHard":["instead of -> instead''a / daily limit là cài đặt chính / deleting them nối","\\"instead of deleting them completely\\" là đoạn cần loop riêng vì chứa thông tin quyết định đáp án.","Hãy nghe từ khóa nội dung trước, rồi mới mở transcript để kiểm tra chi tiết."]}', 77, 'published'),
  ('listening', 'ai-study-tool', 'B2', 'tech-internet', 'AI Study Tool', 'Hai sinh viên bàn cách dùng AI để học, nhưng giảng viên yêu cầu kiểm tra nguồn.', '{"id":"ai-study-tool","title":"AI Study Tool","icon":"ti-light-bulb","tone":"green","goal":"tech-internet","accent":"Canadian","noise":"Class discussion","level":"B2","badge":"AI Listener","baseScore":78,"opening":"Hai sinh viên bàn cách dùng AI để học, nhưng giảng viên yêu cầu kiểm tra nguồn.","story":"Bạn cần nghe lợi ích và cảnh báo.","role":"Sinh viên dùng công cụ học online","target":"Bắt AI, source checking và study advice","transcript":"AI can help you brainstorm, but you still need to check the sources yourself.","nativeLine":"AI can help you brainstorm, but you still needta check the sources yourself.","connectedSpeech":"can là âm yếu / need to -> needta / but báo cảnh báo","hardPart":"check the sources yourself","questionTitle":"Người nói nhắc phải làm gì?","context":"Chọn cảnh báo khi dùng AI.","correct":"Check the sources yourself.","distractors":["Let AI submit the essay.","Ignore all sources."],"keywords":["AI","brainstorm","check","sources"],"missReason":"But chuyển từ lợi ích sang điều bắt buộc phải làm.","mistakes":["reduced","connected","fast"],"label":"Session 78","options":[{"key":"A","text":"Check the sources yourself.","correct":true},{"key":"B","text":"Let AI submit the essay.","correct":false},{"key":"C","text":"Ignore all sources.","correct":false}],"gapParts":["AI can help you brainstorm, but you still need to ",{"answer":"check"}," the ",{"answer":"sources"}," yourself."],"phrases":["AI can help you","brainstorm, but you still","need to check the","sources yourself"],"whyHard":["can là âm yếu / need to -> needta / but báo cảnh báo","\\"check the sources yourself\\" là đoạn cần loop riêng vì chứa thông tin quyết định đáp án.","Hãy nghe từ khóa nội dung trước, rồi mới mở transcript để kiểm tra chi tiết."]}', 78, 'published'),
  ('grammar', 'tu-loai', 'Nền tảng', NULL, 'Từ loại', 'Nhận diện vai trò của từ trong câu để đọc, viết và sửa lỗi chính xác hơn.', '{"id":"tu-loai","order":"01","title":"Từ loại","level":"Nền tảng","time":"18 phút","summary":"Nhận diện vai trò của từ trong câu để đọc, viết và sửa lỗi chính xác hơn.","theory":["Từ loại cho biết một từ đang làm nhiệm vụ gì trong câu: gọi tên sự vật, diễn tả hành động, mô tả đặc điểm, bổ nghĩa hoặc nối ý.","Vị trí trong câu là dấu hiệu quan trọng: danh từ thường làm chủ ngữ hoặc tân ngữ, động từ đứng sau chủ ngữ, tính từ bổ nghĩa danh từ, trạng từ bổ nghĩa động từ, tính từ hoặc cả câu.","Một từ có thể đổi vai trò theo ngữ cảnh, ví dụ study là động từ trong I study English nhưng là danh từ trong a study plan."],"formulas":["Subject + Verb + Object/Complement","Determiner + Adjective + Noun","Adverb + Verb/Adjective/Clause"],"examples":[{"en":"She quickly finished the difficult task.","vi":"She là đại từ, quickly là trạng từ, finished là động từ, difficult là tính từ, task là danh từ."},{"en":"Learning English requires steady practice.","vi":"Learning English làm chủ ngữ; requires là động từ chính."}],"mistakes":["Không dùng tính từ thay cho trạng từ: He speaks fluent English, nhưng He speaks English fluently.","Không chỉ nhìn đuôi từ. Friendly là tính từ dù kết thúc bằng -ly."],"exercises":[{"prompt":"All employees must submit the ___ form by noon.","options":["revise","revised","revision","revising"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - revised."},{"prompt":"The manager spoke ___ about the new company policy.","options":["confident","confidence","confidently","confide"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - confidently."},{"prompt":"The hotel offers ___ rates for corporate clients.","options":["compete","competition","competitive","competitively"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - competitive."},{"prompt":"Please check the ___ of each invoice before approving it.","options":["accurate","accuracy","accurately","accurateness"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - accuracy."},{"prompt":"Ms. Park is responsible for the ___ of new staff members.","options":["train","trained","training","trainer"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - training."},{"prompt":"The technician repaired the printer ___ and efficiently.","options":["quick","quickly","quicker","quickness"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - quickly."},{"prompt":"The company announced a significant ___ in operating costs.","options":["reduce","reduced","reduction","reducing"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - reduction."},{"prompt":"The proposal was ___ accepted by the board of directors.","options":["wide","widely","widen","width"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - widely."},{"prompt":"We need a detailed ___ of last quarter''s sales performance.","options":["analyze","analyst","analytical","analysis"],"answer":3,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: D - analysis."},{"prompt":"The new software is designed to improve employee ___.","options":["productive","productivity","productively","produce"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - productivity."}]}', 1, 'published'),
  ('grammar', 'thi', 'Cốt lõi', NULL, 'Thì', 'Hệ thống đầy đủ 12 thì tiếng Anh theo hiện tại, quá khứ và tương lai.', '{"id":"thi","order":"02","title":"Thì","level":"Cốt lõi","time":"45 phút","summary":"Hệ thống đầy đủ 12 thì tiếng Anh theo hiện tại, quá khứ và tương lai.","theory":["Thì cho biết hành động xảy ra ở hiện tại, quá khứ hay tương lai, đồng thời thể hiện hành động là thói quen, đang tiếp diễn, đã hoàn thành hay kéo dài.","Khi chọn thì, cần xác định mốc thời gian, quan hệ trước-sau của hành động và ý nghĩa muốn nhấn mạnh: sự thật, quá trình, kết quả hay kế hoạch.","Công thức phủ định và nghi vấn thay đổi theo trợ động từ của từng thì: do/does, did, am/is/are, was/were, have/has, had, will."],"sections":[{"title":"I. Nhóm thì hiện tại","items":[{"name":"Present Simple","viName":"Hiện tại đơn","formulas":{"Khẳng định":"S + V(s/es) + O","Phủ định":"S + do/does + not + V nguyên mẫu","Nghi vấn":"Do/Does + S + V nguyên mẫu?"},"uses":["Diễn tả thói quen","Diễn tả sự thật hiển nhiên","Diễn tả lịch trình, thời gian biểu","Diễn tả trạng thái lâu dài"],"signals":["always","usually","often","sometimes","rarely","never","every day","every week"],"examples":["I study English every day.","She goes to school by bus.","The sun rises in the east."]},{"name":"Present Continuous","viName":"Hiện tại tiếp diễn","formulas":{"Khẳng định":"S + am/is/are + V-ing","Phủ định":"S + am/is/are + not + V-ing","Nghi vấn":"Am/Is/Are + S + V-ing?"},"uses":["Diễn tả hành động đang xảy ra ngay lúc nói","Diễn tả hành động tạm thời","Diễn tả kế hoạch gần trong tương lai","Diễn tả sự thay đổi đang diễn ra"],"signals":["now","right now","at the moment","at present","look","listen","today","this week"],"examples":["I am learning English now.","She is watching TV.","They are studying for the exam."]},{"name":"Present Perfect","viName":"Hiện tại hoàn thành","formulas":{"Khẳng định":"S + have/has + V3/ed","Phủ định":"S + have/has + not + V3/ed","Nghi vấn":"Have/Has + S + V3/ed?"},"uses":["Diễn tả hành động đã xảy ra nhưng không nói rõ thời gian","Diễn tả trải nghiệm","Diễn tả hành động bắt đầu trong quá khứ và còn liên quan đến hiện tại","Diễn tả hành động vừa mới xảy ra"],"signals":["already","just","yet","ever","never","recently","lately","so far","up to now","for","since"],"examples":["I have finished my homework.","She has lived here for five years.","Have you ever been to Japan?"]},{"name":"Present Perfect Continuous","viName":"Hiện tại hoàn thành tiếp diễn","formulas":{"Khẳng định":"S + have/has + been + V-ing","Phủ định":"S + have/has + not + been + V-ing","Nghi vấn":"Have/Has + S + been + V-ing?"},"uses":["Nhấn mạnh quá trình của hành động","Hành động bắt đầu trong quá khứ và vẫn đang tiếp tục","Hành động vừa kết thúc nhưng còn để lại kết quả ở hiện tại"],"signals":["for","since","all day","all morning","recently","lately","how long"],"examples":["I have been studying English for two hours.","She has been working all day.","It has been raining since morning."]}]},{"title":"II. Nhóm thì quá khứ","items":[{"name":"Past Simple","viName":"Quá khứ đơn","formulas":{"Khẳng định":"S + V2/ed","Phủ định":"S + did + not + V nguyên mẫu","Nghi vấn":"Did + S + V nguyên mẫu?"},"uses":["Diễn tả hành động đã xảy ra và kết thúc trong quá khứ","Kể lại một chuỗi hành động trong quá khứ","Diễn tả thói quen trong quá khứ"],"signals":["yesterday","last night","last week","last month","last year","ago","in 2020","when I was young"],"examples":["I watched a movie yesterday.","She visited Da Nang last year.","They played football two days ago."]},{"name":"Past Continuous","viName":"Quá khứ tiếp diễn","formulas":{"Khẳng định":"S + was/were + V-ing","Phủ định":"S + was/were + not + V-ing","Nghi vấn":"Was/Were + S + V-ing?"},"uses":["Diễn tả hành động đang xảy ra tại một thời điểm trong quá khứ","Diễn tả hành động đang xảy ra thì hành động khác xen vào","Diễn tả hai hành động xảy ra song song trong quá khứ"],"signals":["at 7 o''clock yesterday","at this time last night","while","when"],"examples":["I was studying at 8 p.m. yesterday.","She was cooking when I came home.","They were playing while I was reading."]},{"name":"Past Perfect","viName":"Quá khứ hoàn thành","formulas":{"Khẳng định":"S + had + V3/ed","Phủ định":"S + had + not + V3/ed","Nghi vấn":"Had + S + V3/ed?"},"uses":["Diễn tả hành động xảy ra trước một hành động khác trong quá khứ","Diễn tả hành động hoàn thành trước một thời điểm trong quá khứ"],"signals":["before","after","by the time","when","already","until"],"examples":["I had finished my homework before I went out.","She had left before I arrived.","By the time we got there, the movie had started."]},{"name":"Past Perfect Continuous","viName":"Quá khứ hoàn thành tiếp diễn","formulas":{"Khẳng định":"S + had + been + V-ing","Phủ định":"S + had + not + been + V-ing","Nghi vấn":"Had + S + been + V-ing?"},"uses":["Nhấn mạnh quá trình của một hành động xảy ra trước một hành động khác trong quá khứ","Diễn tả hành động kéo dài đến trước một thời điểm trong quá khứ"],"signals":["for","since","before","until","by the time"],"examples":["I had been studying for three hours before she called me.","They had been working all day before they went home.","She was tired because she had been running."]}]},{"title":"III. Nhóm thì tương lai","items":[{"name":"Future Simple","viName":"Tương lai đơn","formulas":{"Khẳng định":"S + will + V nguyên mẫu","Phủ định":"S + will not + V nguyên mẫu","Nghi vấn":"Will + S + V nguyên mẫu?"},"uses":["Diễn tả quyết định ngay lúc nói","Dự đoán tương lai","Lời hứa","Lời đề nghị","Lời đe dọa"],"signals":["tomorrow","next week","next month","next year","soon","in the future","one day"],"examples":["I will call you tomorrow.","She will be successful.","I will help you."]},{"name":"Future Continuous","viName":"Tương lai tiếp diễn","formulas":{"Khẳng định":"S + will + be + V-ing","Phủ định":"S + will not + be + V-ing","Nghi vấn":"Will + S + be + V-ing?"},"uses":["Diễn tả hành động đang xảy ra tại một thời điểm trong tương lai","Diễn tả hành động sẽ đang diễn ra theo kế hoạch"],"signals":["at this time tomorrow","at 8 p.m. tomorrow","this time next week","when"],"examples":["I will be studying at 8 p.m. tomorrow.","She will be working this time next week.","They will be traveling tomorrow morning."]},{"name":"Future Perfect","viName":"Tương lai hoàn thành","formulas":{"Khẳng định":"S + will + have + V3/ed","Phủ định":"S + will not + have + V3/ed","Nghi vấn":"Will + S + have + V3/ed?"},"uses":["Diễn tả hành động sẽ hoàn thành trước một thời điểm trong tương lai","Diễn tả hành động sẽ hoàn thành trước một hành động khác trong tương lai"],"signals":["by","by the time","before","by tomorrow","by next week","by the end of this month"],"examples":["I will have finished this project by tomorrow.","She will have left before you arrive.","By next year, I will have graduated."]},{"name":"Future Perfect Continuous","viName":"Tương lai hoàn thành tiếp diễn","formulas":{"Khẳng định":"S + will + have + been + V-ing","Phủ định":"S + will not + have + been + V-ing","Nghi vấn":"Will + S + have + been + V-ing?"},"uses":["Nhấn mạnh quá trình của hành động kéo dài đến một thời điểm trong tương lai","Diễn tả hành động sẽ đã đang diễn ra được bao lâu trước một mốc tương lai"],"signals":["for","since","by","by the time","by next month","by the end of this year"],"examples":["By next month, I will have been studying English for one year.","She will have been working here for ten years by 2030.","They will have been waiting for two hours by the time we arrive."]}]}],"formulas":["Simple: thói quen, sự thật, hành động hoàn tất ở một mốc thời gian","Continuous: hành động đang diễn ra hoặc nhấn mạnh quá trình","Perfect: hành động hoàn thành trước hiện tại/quá khứ/tương lai","Perfect Continuous: hành động kéo dài và nhấn mạnh thời lượng"],"examples":[{"en":"I study English every evening.","vi":"Hiện tại đơn diễn tả thói quen."},{"en":"She has lived here for five years.","vi":"Hiện tại hoàn thành nối quá khứ với hiện tại."},{"en":"By next year, I will have graduated.","vi":"Tương lai hoàn thành nhấn mạnh kết quả trước một mốc tương lai."}],"mistakes":["Khi có mốc before/after trong quá khứ, hành động xảy ra trước thường dùng Past Perfect.","Sau did, do/does, will dùng động từ nguyên mẫu; không chia V2 hoặc thêm s/es."],"exercises":[{"prompt":"By the time Ms. Lee arrived, the meeting ___ already ___.","options":["has / begun","had / begun","was / beginning","will / begin"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - had / begun."},{"prompt":"The sales team ___ the new product line next month.","options":["launches","launched","will launch","has launched"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - will launch."},{"prompt":"Mr. Carter ___ for this company since 2018.","options":["works","worked","has worked","is working"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - has worked."},{"prompt":"The receptionist ___ a phone call when the visitor arrived.","options":["answers","answered","was answering","has answered"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - was answering."},{"prompt":"Our department usually ___ its weekly report on Friday.","options":["submits","submitted","is submitting","has submitted"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - submits."},{"prompt":"The shipment ___ at the warehouse yesterday afternoon.","options":["arrives","arrived","has arrived","will arrive"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - arrived."},{"prompt":"We ___ the contract before the client requested changes.","options":["finalize","finalized","had finalized","will finalize"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - had finalized."},{"prompt":"The company ___ a new branch in Manila next year.","options":["opened","has opened","opens","will open"],"answer":3,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: D - will open."},{"prompt":"I ___ the budget figures right now, so I cannot join the call.","options":["review","reviewed","am reviewing","have reviewed"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - am reviewing."},{"prompt":"The training session ___ by the time you return from lunch.","options":["ends","ended","will have ended","has ended"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - will have ended."}]}', 2, 'published'),
  ('grammar', 'danh-tu', 'Nền tảng', NULL, 'Danh từ', 'Dùng danh từ đếm được, không đếm được, số ít/số nhiều và sở hữu đúng ngữ cảnh.', '{"id":"danh-tu","order":"03","title":"Danh từ","level":"Nền tảng","time":"20 phút","summary":"Dùng danh từ đếm được, không đếm được, số ít/số nhiều và sở hữu đúng ngữ cảnh.","theory":["Danh từ gọi tên người, vật, nơi chốn, ý tưởng hoặc khái niệm.","Danh từ đếm được có số ít và số nhiều; danh từ không đếm được thường không dùng a/an và không thêm s.","Sở hữu cách dùng ''s cho người/vật sống hoặc of cho vật/khái niệm.","Khi viết câu, hãy xác định danh từ đang là chủ ngữ, tân ngữ hay bổ ngữ để chọn đúng mạo từ, lượng từ và dạng số nhiều.","Danh từ tập hợp như team, family, staff có thể nhấn mạnh cả nhóm hoặc từng thành viên tùy ngữ cảnh."],"formulas":["a/an + singular countable noun","some/any + plural noun/uncountable noun","Noun + ''s + noun","a/an + singular countable noun","some/any + plural countable noun or uncountable noun","noun + ''s / of + noun"],"examples":[{"en":"There are three students in the room.","vi":"Students là danh từ số nhiều đếm được."},{"en":"I need some advice.","vi":"Advice là danh từ không đếm được."},{"en":"The team is preparing its final report.","vi":"Team được xem như một đơn vị nên dùng is và its."},{"en":"I need two pieces of advice.","vi":"Advice không đếm được, cần dùng piece of advice khi muốn đếm."}],"mistakes":["Không dùng a/an trước danh từ số nhiều hoặc không đếm được.","Một số danh từ số nhiều bất quy tắc: child -> children, person -> people, knife -> knives.","Không thêm s cho information, furniture, homework, equipment.","Không dùng a/an với danh từ không đếm được."],"exercises":[{"prompt":"The company received several ___ from customers after the update.","options":["complaint","complaints","complain","complaining"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - complaints."},{"prompt":"We need more ___ before making a final decision.","options":["information","informations","informative","inform"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - information."},{"prompt":"The ___ suggestions were discussed during the meeting.","options":["employees","employee''s","employees''","employee"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - employees''."},{"prompt":"Please send me two ___ of the signed agreement.","options":["copy","copies","copying","copied"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - copies."},{"prompt":"The restaurant''s new menu includes several vegetarian ___.","options":["option","options","optional","optionally"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - options."},{"prompt":"Ms. Brown has ten years of ___ in project management.","options":["experience","experiences","experienced","experiencing"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - experience."},{"prompt":"The marketing team prepared a list of potential ___.","options":["client","clients","client''s","cliented"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - clients."},{"prompt":"The ___ report must be submitted before the end of the month.","options":["accountant","accounting","account","accounted"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - accounting."},{"prompt":"The director reviewed the ___ performance carefully.","options":["department","departments","department''s","departmental"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - department''s."},{"prompt":"All ___ must wear identification badges in the building.","options":["visitor","visitors","visiting","visits"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - visitors."}]}', 3, 'published'),
  ('grammar', 'dong-tu', 'Nền tảng', NULL, 'Động từ', 'Nắm động từ chính, trợ động từ, nội động từ, ngoại động từ và mẫu động từ.', '{"id":"dong-tu","order":"04","title":"Động từ","level":"Nền tảng","time":"21 phút","summary":"Nắm động từ chính, trợ động từ, nội động từ, ngoại động từ và mẫu động từ.","theory":["Động từ diễn tả hành động, trạng thái hoặc sự tồn tại.","Ngoại động từ cần tân ngữ trực tiếp; nội động từ không cần tân ngữ trực tiếp.","Trợ động từ như do, be, have, will giúp tạo phủ định, câu hỏi, thì và thể bị động.","Động từ quyết định khung câu: có động từ cần tân ngữ, có động từ cần tính từ bổ nghĩa, có động từ đi với V-ing hoặc to V.","Trợ động từ như do, be, have giúp tạo câu hỏi, phủ định, tiếp diễn và hoàn thành."],"formulas":["S + intransitive verb","S + transitive verb + object","Auxiliary + S + main verb?","Subject + transitive verb + object","Subject + linking verb + adjective/noun","Modal verb + base verb"],"examples":[{"en":"She sleeps early.","vi":"Sleep là nội động từ."},{"en":"They built a house.","vi":"Build là ngoại động từ và cần tân ngữ a house."},{"en":"The soup tastes salty.","vi":"Taste là linking verb, phía sau dùng tính từ salty."},{"en":"She explained the rule clearly.","vi":"Explain là ngoại động từ, cần tân ngữ the rule."}],"mistakes":["Không bỏ trợ động từ trong câu hỏi: Do you like music?","Sau modal verbs dùng động từ nguyên mẫu không to.","Không dùng to sau modal verbs: can go, must study.","Không bỏ tân ngữ với các động từ cần tân ngữ như discuss, explain, attend."],"exercises":[{"prompt":"The manager ___ the final report before sending it to headquarters.","options":["reviewed","review","reviewing","reviews to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - reviewed."},{"prompt":"Please ___ the attached document carefully.","options":["read","reading","to read","reads"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - read."},{"prompt":"The new policy will ___ all full-time employees.","options":["apply","affect","happen","arrive"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - affect."},{"prompt":"The technician ___ the broken scanner this morning.","options":["fixed","fixing","fixes to","was fixed"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - fixed."},{"prompt":"Our team ___ a solution to the delivery problem.","options":["came up with","came over","came across","came down"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - came up with."},{"prompt":"The CEO ___ the importance of customer satisfaction.","options":["emphasized","emphasized on","emphasized to","emphasized about"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - emphasized."},{"prompt":"The company ___ several candidates for the position.","options":["interviewed","interviewed with","interviewed to","was interviewed"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - interviewed."},{"prompt":"The meeting ___ at exactly 9 a.m.","options":["began","was begun","beginning","begins to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - began."},{"prompt":"The supplier failed to ___ the goods on time.","options":["delivery","deliver","delivered","delivering"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - deliver."},{"prompt":"Employees are encouraged to ___ any safety concerns immediately.","options":["report","reporting","reported","reports"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - report."}]}', 4, 'published'),
  ('grammar', 'tinh-tu', 'Nền tảng', NULL, 'Tính từ', 'Mô tả danh từ, dùng linking verbs và sắp xếp nhiều tính từ đúng thứ tự.', '{"id":"tinh-tu","order":"05","title":"Tính từ","level":"Nền tảng","time":"18 phút","summary":"Mô tả danh từ, dùng linking verbs và sắp xếp nhiều tính từ đúng thứ tự.","theory":["Tính từ mô tả đặc điểm, trạng thái hoặc tính chất của danh từ.","Tính từ có thể đứng trước danh từ hoặc sau linking verbs như be, seem, become, feel.","Khi có nhiều tính từ, thứ tự thường là opinion, size, age, shape, color, origin, material, purpose.","Tính từ nêu phẩm chất, trạng thái, kích thước, tuổi, màu sắc, nguồn gốc hoặc chất liệu của danh từ.","Một số tính từ kết thúc bằng -ed mô tả cảm xúc của người; -ing mô tả thứ gây ra cảm xúc đó."],"formulas":["adjective + noun","S + linking verb + adjective","too/very/quite + adjective","linking verb + adjective","opinion + size + age + shape + color + origin + material + noun","so/too/very + adjective"],"examples":[{"en":"It is a beautiful old house.","vi":"Beautiful là ý kiến, old là tuổi."},{"en":"The soup tastes delicious.","vi":"Delicious đứng sau linking verb tastes."},{"en":"The lesson was confusing, so I felt confused.","vi":"Confusing mô tả bài học; confused mô tả cảm xúc của người học."},{"en":"She bought a beautiful small wooden box.","vi":"Beautiful, small, wooden đứng theo thứ tự tự nhiên trước danh từ."}],"mistakes":["Không thêm s cho tính từ khi danh từ số nhiều: beautiful houses.","Không dùng trạng từ sau linking verb nếu cần mô tả chủ ngữ: She looks happy.","Không dùng trạng từ sau linking verbs: feel happy, không phải feel happily.","Không đặt nhiều tính từ tùy tiện trước danh từ."],"exercises":[{"prompt":"The new office furniture is both comfortable and ___.","options":["durability","durable","durably","endure"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - durable."},{"prompt":"The report provides a ___ summary of the company''s performance.","options":["brief","briefly","briefing","briefness"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - brief."},{"prompt":"Customers were pleased with the ___ service.","options":["prompt","promptly","promptness","prompted"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - prompt."},{"prompt":"This is the most ___ proposal we have received so far.","options":["impress","impressive","impressively","impression"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - impressive."},{"prompt":"The conference room looks ___ after the renovation.","options":["modern","modernly","modernize","modernity"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - modern."},{"prompt":"We ordered three ___ leather office chairs.","options":["black large Italian","Italian black large","large black Italian","black Italian large"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - large black Italian."},{"prompt":"The instructions were clear and easy to ___.","options":["follow","following","followed","follows"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - follow."},{"prompt":"The new manager seems ___ with the team''s progress.","options":["satisfy","satisfied","satisfaction","satisfactorily"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - satisfied."},{"prompt":"The company is looking for a ___ candidate with strong communication skills.","options":["qualify","qualified","qualification","qualifyingly"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - qualified."},{"prompt":"The delay was caused by ___ weather conditions.","options":["severe","severely","severity","severeness"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - severe."}]}', 5, 'published'),
  ('grammar', 'trang-tu', 'Nền tảng', NULL, 'Trạng từ', 'Bổ nghĩa cho động từ, tính từ, trạng từ khác hoặc cả câu.', '{"id":"trang-tu","order":"06","title":"Trạng từ","level":"Nền tảng","time":"18 phút","summary":"Bổ nghĩa cho động từ, tính từ, trạng từ khác hoặc cả câu.","theory":["Trạng từ trả lời các câu hỏi how, when, where, how often và to what degree.","Nhiều trạng từ cách thức được tạo bằng adjective + ly, nhưng có ngoại lệ như fast, hard, well.","Vị trí trạng từ phụ thuộc vào loại trạng từ và ý muốn nhấn mạnh.","Trạng từ có thể bổ nghĩa cho hành động, mức độ, tần suất, thời gian, nơi chốn hoặc thái độ của cả câu.","Vị trí trạng từ thay đổi theo loại: trạng từ tần suất thường đứng trước động từ thường, sau be."],"formulas":["S + V + adverb","adverb + adjective","frequency adverb + main verb","frequency adverb + main verb","be + frequency adverb","verb + manner adverb"],"examples":[{"en":"He speaks English fluently.","vi":"Fluently bổ nghĩa cho speaks."},{"en":"She usually gets up early.","vi":"Usually diễn tả tần suất."},{"en":"She usually studies after dinner.","vi":"Usually đứng trước động từ thường studies."},{"en":"He answered the question surprisingly well.","vi":"Surprisingly bổ nghĩa cho well, well bổ nghĩa cho answered."}],"mistakes":["Không nhầm hard và hardly: hard là chăm chỉ/mạnh, hardly là hầu như không.","Không dùng good thay cho well khi bổ nghĩa cho động từ.","Hard là trạng từ nghĩa là chăm chỉ/mạnh, hardly nghĩa là hầu như không.","Không phải trạng từ nào cũng thêm -ly: fast, late, well."],"exercises":[{"prompt":"The finance team reviewed the budget ___ before approval.","options":["careful","carefully","care","carefulness"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - carefully."},{"prompt":"The package arrived ___ than expected.","options":["early","earlier","earliest","earliness"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - earlier."},{"prompt":"Mr. Johnson responded ___ to the client''s complaint.","options":["immediate","immediately","immediacy","more immediate"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - immediately."},{"prompt":"The new software runs ___ on older computers.","options":["smoothly","smooth","smoothness","smoother"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - smoothly."},{"prompt":"Employees must dress ___ for client meetings.","options":["professional","professionally","profession","professionalism"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - professionally."},{"prompt":"The marketing campaign was ___ successful.","options":["high","height","highly","higher"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - highly."},{"prompt":"Please speak ___ during the presentation so everyone can hear you.","options":["clear","clearly","clarity","clearing"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - clearly."},{"prompt":"The shipment was ___ delayed due to bad weather.","options":["unexpected","unexpectedly","expecting","expectation"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - unexpectedly."},{"prompt":"The director ___ approved the revised proposal.","options":["final","finally","finalize","finality"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - finally."},{"prompt":"The receptionist handled the situation very ___.","options":["calm","calmly","calming","calmness"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - calmly."}]}', 6, 'published'),
  ('grammar', 'mao-tu', 'Cốt lõi', NULL, 'Mạo từ', 'Dùng a, an, the và trường hợp không dùng mạo từ chính xác hơn.', '{"id":"mao-tu","order":"07","title":"Mạo từ","level":"Cốt lõi","time":"20 phút","summary":"Dùng a, an, the và trường hợp không dùng mạo từ chính xác hơn.","theory":["A/an dùng với danh từ đếm được số ít khi nhắc lần đầu hoặc chưa xác định.","The dùng khi người nghe đã biết đối tượng, đối tượng là duy nhất hoặc đã được nhắc trước đó.","Không dùng mạo từ trước danh từ số nhiều/không đếm được khi nói chung.","Mạo từ giúp người nghe biết danh từ đang được nói chung, nhắc lần đầu hay đã xác định.","Âm đầu quyết định a/an, không phải chữ cái đầu: an hour, a university."],"formulas":["a/an + singular countable noun","the + specific noun","zero article + general plural/uncountable noun","a/an + singular countable noun","the + specific noun","zero article + plural/general noun"],"examples":[{"en":"I saw a dog. The dog was friendly.","vi":"A dùng khi nhắc lần đầu, the dùng khi nhắc lại."},{"en":"Water is important.","vi":"Water nói chung nên không dùng mạo từ."},{"en":"I saw a dog. The dog was very small.","vi":"A dùng khi nhắc lần đầu; the dùng khi người nghe đã biết con chó nào."},{"en":"Children need time to play.","vi":"Children nói chung nên không dùng the."}],"mistakes":["An phụ thuộc vào âm bắt đầu, không chỉ chữ cái: an hour, a university.","Không dùng the khi nói chung: I like music.","Không dùng the khi nói khái quát về danh từ số nhiều.","Không quên mạo từ trước danh từ đếm được số ít."],"exercises":[{"prompt":"Ms. Adams is ___ experienced consultant in international trade.","options":["a","an","the","no article"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - an."},{"prompt":"The company opened ___ new branch near the airport.","options":["a","an","the","no article"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - a."},{"prompt":"Please send the file to ___ accounting department.","options":["a","an","the","no article"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - the."},{"prompt":"We need to hire ___ engineer for the new project.","options":["a","an","the","no article"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - an."},{"prompt":"___ information you requested is attached to this email.","options":["A","An","The","No article"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - The."},{"prompt":"Our office is located on ___ third floor.","options":["a","an","the","no article"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - the."},{"prompt":"Employees must wear ___ uniform during working hours.","options":["a","an","the","no article"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - a."},{"prompt":"Mr. Wilson gave us ___ useful advice about the presentation.","options":["a","an","the","no article"],"answer":3,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: D - no article."},{"prompt":"The meeting will be held in ___ Room 204.","options":["a","an","the","no article"],"answer":3,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: D - no article."},{"prompt":"She is ___ best candidate for the position.","options":["a","an","the","no article"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - the."}]}', 7, 'published'),
  ('grammar', 'gioi-tu', 'Cốt lõi', NULL, 'Giới từ', 'Dùng giới từ chỉ thời gian, nơi chốn, hướng di chuyển và cụm cố định.', '{"id":"gioi-tu","order":"08","title":"Giới từ","level":"Cốt lõi","time":"22 phút","summary":"Dùng giới từ chỉ thời gian, nơi chốn, hướng di chuyển và cụm cố định.","theory":["Giới từ thể hiện quan hệ giữa danh từ/cụm danh từ với phần còn lại của câu.","At, on, in có quy tắc riêng cho thời gian và nơi chốn.","Nhiều giới từ đi theo cụm cố định, cần học theo cụm thay vì dịch từng từ.","Giới từ thường đi theo cụm cố định, vì vậy cần học theo cụm như interested in, good at, responsible for.","At nhấn điểm cụ thể, on nhấn bề mặt/ngày, in nhấn không gian hoặc khoảng thời gian rộng."],"formulas":["at + exact time/place","on + day/date/surface","in + month/year/area","adjective + preposition","verb + preposition + object","preposition + noun phrase"],"examples":[{"en":"The meeting starts at 9 a.m.","vi":"At dùng với giờ cụ thể."},{"en":"She lives in Hanoi.","vi":"In dùng với thành phố/khu vực."},{"en":"She is responsible for the schedule.","vi":"Responsible thường đi với for."},{"en":"We met at the station on Friday in March.","vi":"At địa điểm cụ thể, on ngày, in tháng."}],"mistakes":["Không dịch máy từng giới từ từ tiếng Việt sang tiếng Anh; hãy học theo cụm.","Arrive dùng arrive in với thành phố/quốc gia và arrive at với địa điểm cụ thể.","Không dịch từng chữ giới từ từ tiếng Việt sang tiếng Anh.","Không dùng in Monday; ngày trong tuần dùng on."],"exercises":[{"prompt":"The meeting is scheduled ___ Monday morning.","options":["in","on","at","by"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - on."},{"prompt":"Please submit your report ___ the end of the day.","options":["on","at","by","in"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - by."},{"prompt":"The office is located ___ the second floor.","options":["at","in","on","to"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - on."},{"prompt":"We are interested ___ expanding into new markets.","options":["in","on","at","for"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - in."},{"prompt":"The manager is responsible ___ training new employees.","options":["with","for","to","about"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - for."},{"prompt":"The package was delivered ___ the wrong address.","options":["in","at","to","on"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to."},{"prompt":"The seminar will take place ___ 9 a.m. and noon.","options":["among","between","during","through"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - between."},{"prompt":"Sales increased ___ 15 percent last quarter.","options":["by","to","with","from"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - by."},{"prompt":"The report must be completed ___ Friday.","options":["until","by","since","during"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - by."},{"prompt":"The company has been in business ___ more than twenty years.","options":["since","during","for","at"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - for."}]}', 8, 'published'),
  ('grammar', 'so-sanh', 'Cốt lõi', NULL, 'So sánh', 'Dùng so sánh bằng, hơn, nhất và các dạng bất quy tắc.', '{"id":"so-sanh","order":"09","title":"So sánh","level":"Cốt lõi","time":"22 phút","summary":"Dùng so sánh bằng, hơn, nhất và các dạng bất quy tắc.","theory":["So sánh bằng dùng as + adjective/adverb + as.","So sánh hơn dùng adjective-er hoặc more + adjective, tùy độ dài của tính từ.","So sánh nhất dùng the + adjective-est hoặc the most + adjective.","So sánh hơn nhấn sự khác biệt giữa hai đối tượng; so sánh nhất nhấn một đối tượng nổi bật trong một nhóm.","Tính từ ngắn thường thêm -er/-est; tính từ dài dùng more/most; một số từ bất quy tắc cần học riêng."],"formulas":["as + adj/adv + as","comparative + than","the + superlative","comparative + than","the + superlative + noun","as + adjective/adverb + as"],"examples":[{"en":"This book is more interesting than that one.","vi":"Interesting dùng more vì là tính từ dài."},{"en":"She is the tallest student in class.","vi":"Tall dùng tallest ở so sánh nhất."},{"en":"This route is less crowded than the main road.","vi":"Less dùng để so sánh mức độ ít hơn."},{"en":"It is one of the most useful tools.","vi":"One of đi với the most và danh từ số nhiều."}],"mistakes":["Không dùng more với tính từ đã thêm -er: more faster là sai.","Một số dạng bất quy tắc: good -> better -> best, bad -> worse -> worst.","Không dùng more better hoặc most easiest.","Sau than cần đối tượng được so sánh rõ ràng."],"exercises":[{"prompt":"This year''s sales figures are ___ than last year''s.","options":["high","higher","highest","highly"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - higher."},{"prompt":"The new printer is ___ efficient than the old one.","options":["more","most","much","many"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - more."},{"prompt":"This is the ___ conference room in the building.","options":["large","larger","largest","largely"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - largest."},{"prompt":"Ms. Green speaks English ___ than anyone else on the team.","options":["fluently","more fluently","most fluently","fluent"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - more fluently."},{"prompt":"The revised proposal is ___ as detailed as the original version.","options":["so","as","more","most"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - as."},{"prompt":"The second interview was much ___ than the first one.","options":["difficult","more difficult","most difficult","difficulty"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - more difficult."},{"prompt":"This model is less expensive ___ the previous one.","options":["as","than","from","to"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - than."},{"prompt":"Of all the applicants, Mr. Chen has the ___ qualifications.","options":["strong","stronger","strongest","strongly"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - strongest."},{"prompt":"The new system works ___ than we expected.","options":["well","better","best","good"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - better."},{"prompt":"The earlier you submit the form, the ___ it can be processed.","options":["fast","faster","fastest","more fast"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - faster."}]}', 9, 'published'),
  ('grammar', 'modal-verbs', 'Cốt lõi', NULL, 'Modal verbs', 'Dùng can, could, may, might, must, should, would để diễn tả khả năng, lời khuyên và nghĩa vụ.', '{"id":"modal-verbs","order":"10","title":"Modal verbs","level":"Cốt lõi","time":"20 phút","summary":"Dùng can, could, may, might, must, should, would để diễn tả khả năng, lời khuyên và nghĩa vụ.","theory":["Modal verbs đứng trước động từ nguyên mẫu không to.","Can/could diễn tả khả năng hoặc lời nhờ; may/might diễn tả khả năng; must/have to diễn tả nghĩa vụ; should diễn tả lời khuyên.","Modal verbs không thêm s theo chủ ngữ và không dùng thêm do/does trong câu hỏi.","Modal verbs thể hiện thái độ của người nói: khả năng, mức độ chắc chắn, lời khuyên, sự cho phép hoặc nghĩa vụ.","Modal verbs không chia theo chủ ngữ và động từ sau modal luôn ở dạng nguyên mẫu."],"formulas":["S + modal + base verb","Modal + S + base verb?","S + modal + not + base verb","modal + base verb","modal + not + base verb","modal + subject + base verb?"],"examples":[{"en":"You should review the lesson.","vi":"Should đưa ra lời khuyên."},{"en":"She can swim very well.","vi":"Can diễn tả khả năng."},{"en":"You should review the notes before class.","vi":"Should đưa ra lời khuyên."},{"en":"The package might arrive today.","vi":"Might diễn tả khả năng không chắc chắn."}],"mistakes":["Không viết she cans hoặc must to go.","Must not là cấm làm; do not have to là không cần làm.","Không dùng to sau should, must, can.","Must not là cấm; don''t have to là không cần, hai nghĩa khác nhau."],"exercises":[{"prompt":"Employees ___ wear their ID badges at all times.","options":["must","might","would","could"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - must."},{"prompt":"You ___ submit the application online or in person.","options":["may","must to","should to","can to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - may."},{"prompt":"The delivery ___ arrive later than expected because of heavy traffic.","options":["must","might","should","would"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - might."},{"prompt":"We ___ review the contract before signing it.","options":["should","may to","can to","must to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - should."},{"prompt":"Mr. Lee ___ attend the meeting yesterday because he was sick.","options":["cannot","could not","must not","may not"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - could not."},{"prompt":"Visitors ___ enter the laboratory without permission.","options":["must not","would not","might not","could not"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - must not."},{"prompt":"The manager said we ___ leave early after finishing the report.","options":["could","must","should to","can to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - could."},{"prompt":"You ___ contact customer service if the problem continues.","options":["had better","would better","must better","may better"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - had better."},{"prompt":"The figures ___ be correct because they match the accounting records.","options":["must","might","could","would"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - must."},{"prompt":"___ you please send me the updated schedule?","options":["Must","Should","Could","May to"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - Could."}]}', 10, 'published'),
  ('grammar', 'cau-dieu-kien', 'Ứng dụng', NULL, 'Câu điều kiện', 'Dùng câu điều kiện loại 0, 1, 2, 3 và mixed conditionals đúng ngữ cảnh.', '{"id":"cau-dieu-kien","order":"11","title":"Câu điều kiện","level":"Ứng dụng","time":"26 phút","summary":"Dùng câu điều kiện loại 0, 1, 2, 3 và mixed conditionals đúng ngữ cảnh.","theory":["Câu điều kiện gồm mệnh đề if và mệnh đề chính.","Loại 0 nói về sự thật chung; loại 1 nói về khả năng thật trong tương lai.","Loại 2 nói về giả định hiện tại/tương lai; loại 3 nói về giả định trái với quá khứ.","Câu điều kiện cần khớp giữa mức độ thật/giả định và thời gian của kết quả.","Nếu mệnh đề if đứng đầu câu, thường dùng dấu phẩy trước mệnh đề chính."],"formulas":["If + Present Simple, S + Present Simple","If + Present Simple, S + will + V","If + Past Simple, S + would + V","If + Past Perfect, S + would have + V3/ed","If + present simple, will + base verb","If + past simple, would + base verb","If + past perfect, would have + V3"],"examples":[{"en":"If it rains, I will stay home.","vi":"Điều kiện loại 1."},{"en":"If I had studied harder, I would have passed.","vi":"Điều kiện loại 3."},{"en":"If you heat water to 100°C, it boils.","vi":"Loại 0 nói về sự thật chung."},{"en":"If I had left earlier, I would have caught the bus.","vi":"Loại 3 nói về điều không xảy ra trong quá khứ."}],"mistakes":["Không dùng will trong mệnh đề if của điều kiện loại 1: If it rains, not If it will rain.","Were thường dùng với mọi chủ ngữ trong giả định trang trọng: If I were you.","Không dùng will trong mệnh đề if của điều kiện loại 1.","Không trộn loại 2 và loại 3 nếu không có ý mixed conditional rõ ràng."],"exercises":[{"prompt":"If the shipment arrives today, we ___ it to the client immediately.","options":["send","sent","will send","would send"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - will send."},{"prompt":"If employees have questions, they ___ contact the HR department.","options":["can","could have","would have","had"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - can."},{"prompt":"If we had ordered more supplies, we ___ enough folders for everyone.","options":["have","had","would have had","will have"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - would have had."},{"prompt":"If I were the manager, I ___ the meeting schedule.","options":["change","changed","would change","will change"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - would change."},{"prompt":"If customers are dissatisfied, they usually ___ a refund.","options":["request","requested","will requested","would requested"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - request."},{"prompt":"If the printer stops working again, ___ the IT department.","options":["call","called","calling","to call"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - call."},{"prompt":"If the company had invested earlier, it ___ more competitive now.","options":["is","will be","would be","would have been"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - would be."},{"prompt":"Unless the report is submitted today, it ___ included in the review.","options":["is not","will not be","would not","has not"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - will not be."},{"prompt":"If I ___ your email earlier, I would have replied sooner.","options":["see","saw","had seen","have seen"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - had seen."},{"prompt":"If the weather improves, the outdoor event ___ as planned.","options":["continues","continued","will continue","would continue"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - will continue."}]}', 11, 'published'),
  ('grammar', 'cau-bi-dong', 'Ứng dụng', NULL, 'Câu bị động', 'Chuyển trọng tâm từ người làm hành động sang đối tượng chịu tác động.', '{"id":"cau-bi-dong","order":"12","title":"Câu bị động","level":"Ứng dụng","time":"24 phút","summary":"Chuyển trọng tâm từ người làm hành động sang đối tượng chịu tác động.","theory":["Câu bị động dùng khi người/vật chịu tác động quan trọng hơn người thực hiện hành động.","Cấu trúc cốt lõi là be + V3/ed, trong đó be chia theo thì của câu.","By + tác nhân chỉ dùng khi tác nhân quan trọng hoặc cần làm rõ.","Câu bị động hữu ích khi đối tượng chịu tác động quan trọng hơn người thực hiện hành động.","By + agent chỉ dùng khi người thực hiện hành động thật sự cần thiết."],"formulas":["S + be + V3/ed","S + modal + be + V3/ed","S + have/has + been + V3/ed","object + be + V3/ed","object + modal + be + V3/ed","object + have/has been + V3/ed"],"examples":[{"en":"The report was finished yesterday.","vi":"Was finished là bị động quá khứ đơn."},{"en":"This room is cleaned every day.","vi":"Is cleaned là bị động hiện tại đơn."},{"en":"The report has been updated.","vi":"Hiện tại hoàn thành bị động: has been updated."},{"en":"The meeting can be moved to Friday.","vi":"Modal bị động: can be moved."}],"mistakes":["Không quên chia be theo thì: was built, is built, will be built.","Không dùng bị động với nội động từ không có tân ngữ trực tiếp.","Không quên chia be theo thì của câu.","Không dùng bị động với động từ nội động không có tân ngữ như happen, arrive, sleep."],"exercises":[{"prompt":"The annual report ___ by the finance department.","options":["prepared","was prepared","preparing","has preparing"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - was prepared."},{"prompt":"All applications must ___ by Friday.","options":["submit","submitted","be submitted","submitting"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - be submitted."},{"prompt":"The meeting room ___ every morning.","options":["cleans","cleaned","is cleaned","cleaning"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - is cleaned."},{"prompt":"The new software ___ next week.","options":["will install","will be installed","installed","installing"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - will be installed."},{"prompt":"The invitations have already ___ to all participants.","options":["sent","been sent","sending","send"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - been sent."},{"prompt":"The damaged items ___ from the warehouse yesterday.","options":["removed","were removed","removing","have removing"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - were removed."},{"prompt":"The contract is being ___ by our legal team.","options":["review","reviewed","reviewing","reviews"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - reviewed."},{"prompt":"The final decision ___ after the board meeting.","options":["will make","will be made","made","has made"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - will be made."},{"prompt":"Customers are ___ to complete a short survey.","options":["encourage","encouraged","encouraging","encouragement"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - encouraged."},{"prompt":"The equipment should ___ carefully before use.","options":["inspect","inspected","be inspected","inspecting"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - be inspected."}]}', 12, 'published'),
  ('grammar', 'cau-tuong-thuat', 'Ứng dụng', NULL, 'Câu tường thuật', 'Tường thuật lời nói, câu hỏi và mệnh lệnh với lùi thì, đổi đại từ và trạng từ thời gian.', '{"id":"cau-tuong-thuat","order":"13","title":"Câu tường thuật","level":"Ứng dụng","time":"25 phút","summary":"Tường thuật lời nói, câu hỏi và mệnh lệnh với lùi thì, đổi đại từ và trạng từ thời gian.","theory":["Câu tường thuật chuyển lời nói trực tiếp sang gián tiếp.","Khi động từ tường thuật ở quá khứ, thường lùi thì: present -> past, past -> past perfect, will -> would.","Đại từ, trạng từ chỉ thời gian và nơi chốn cần đổi theo ngữ cảnh.","Câu tường thuật cần đổi đại từ, trạng từ thời gian/nơi chốn và thường lùi thì khi động từ tường thuật ở quá khứ.","Câu hỏi gián tiếp dùng trật tự câu kể, không đảo trợ động từ như câu hỏi trực tiếp."],"formulas":["S + said/told + (that) + clause","S + asked + if/whether + clause","S + told/asked + O + to V","said that + clause","asked + object + if/whether + clause","told + object + to V"],"examples":[{"en":"He said that he was tired.","vi":"I am tired đổi thành he was tired."},{"en":"She asked me where I lived.","vi":"Câu hỏi gián tiếp dùng trật tự câu kể."},{"en":"She said that she was working from home.","vi":"Am working lùi thành was working."},{"en":"He asked me where I lived.","vi":"Câu hỏi gián tiếp dùng I lived, không dùng did I live."}],"mistakes":["Không giữ trật tự câu hỏi trong câu hỏi gián tiếp: where you live là sai trong She asked where you lived.","Tell cần tân ngữ: told me, told him.","Không giữ nguyên today, tomorrow, here nếu ngữ cảnh đã đổi.","Không dùng said me; dùng told me hoặc said to me."],"exercises":[{"prompt":"Mr. Adams said that he ___ the report by Friday.","options":["finishes","will finish","would finish","finish"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - would finish."},{"prompt":"She asked whether the meeting ___ been postponed.","options":["has","had","have","having"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - had."},{"prompt":"The manager told us ___ late for the conference.","options":["not be","not to be","do not be","not being"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - not to be."},{"prompt":"Ms. Taylor said she ___ the client the previous day.","options":["meets","met","had met","has met"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - had met."},{"prompt":"He asked me where I ___ the files.","options":["store","stored","storing","stores"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - stored."},{"prompt":"The supervisor said that the office ___ closed on Monday.","options":["is","was","has","will"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - was."},{"prompt":"They asked if we ___ available for a meeting the next morning.","options":["are","were","will be","have been"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - were."},{"prompt":"The director told employees ___ their passwords regularly.","options":["update","updating","to update","updated"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to update."},{"prompt":"Sarah said that she ___ working on the budget at that moment.","options":["is","was","has been","will be"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - was."},{"prompt":"The client asked when the shipment ___.","options":["arrives","arrived","would arrive","arriving"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - would arrive."}]}', 13, 'published'),
  ('grammar', 'menh-de-quan-he', 'Ứng dụng', NULL, 'Mệnh đề quan hệ', 'Dùng who, whom, which, that, whose, where, when để bổ sung thông tin cho danh từ.', '{"id":"menh-de-quan-he","order":"14","title":"Mệnh đề quan hệ","level":"Ứng dụng","time":"24 phút","summary":"Dùng who, whom, which, that, whose, where, when để bổ sung thông tin cho danh từ.","theory":["Mệnh đề quan hệ bổ nghĩa cho danh từ đứng trước nó.","Who dùng cho người làm chủ ngữ; whom dùng cho người làm tân ngữ; which dùng cho vật; whose chỉ sở hữu.","Mệnh đề xác định không dùng dấu phẩy; mệnh đề không xác định dùng dấu phẩy và không dùng that.","Mệnh đề quan hệ giúp nối câu và tránh lặp danh từ, nhưng cần phân biệt thông tin thiết yếu và thông tin bổ sung.","Mệnh đề không xác định cần dấu phẩy và không dùng that thay cho who/which."],"formulas":["Noun + who/which/that + clause","Noun + whose + noun + clause","Place + where + clause","noun + who/which/that + verb","noun + whose + noun","place + where + clause"],"examples":[{"en":"The woman who lives next door is a doctor.","vi":"Who bổ nghĩa cho the woman."},{"en":"This is the book that I told you about.","vi":"That thay cho the book."},{"en":"The app that I use every day is simple.","vi":"That thay cho app và làm tân ngữ trong mệnh đề quan hệ."},{"en":"My brother, who lives in Hue, is a teacher.","vi":"Thông tin bổ sung nên đặt giữa hai dấu phẩy."}],"mistakes":["Không dùng that trong mệnh đề quan hệ không xác định.","Whose đi với danh từ phía sau: whose car, whose idea.","Không dùng where cho người hoặc vật không phải nơi chốn.","Không bỏ dấu phẩy trong mệnh đề quan hệ không xác định."],"exercises":[{"prompt":"The employee ___ submitted the report early received praise.","options":["who","which","where","when"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - who."},{"prompt":"The laptop ___ I purchased last month has already stopped working.","options":["who","whose","which","where"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - which."},{"prompt":"The hotel ___ we stayed during the conference was excellent.","options":["when","where","which","whose"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - where."},{"prompt":"The manager ___ office is on the fifth floor is unavailable today.","options":["who","whom","whose","which"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - whose."},{"prompt":"The restaurant ___ opened downtown is already very popular.","options":["who","that","where","whose"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - that."},{"prompt":"The applicant ___ we interviewed yesterday has strong experience.","options":["whom","which","whose","where"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - whom."},{"prompt":"The day ___ the product was launched was extremely busy.","options":["where","when","which","whose"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - when."},{"prompt":"The company has hired a consultant ___ specializes in digital marketing.","options":["who","which","where","when"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - who."},{"prompt":"The document ___ you requested is attached to this email.","options":["who","whose","that","where"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - that."},{"prompt":"The city ___ our new branch is located has excellent transportation.","options":["which","where","when","whose"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - where."}]}', 14, 'published'),
  ('grammar', 'gerund-infinitive', 'Ứng dụng', NULL, 'Gerund / Infinitive', 'Chọn V-ing hoặc to V sau động từ, giới từ và tính từ.', '{"id":"gerund-infinitive","order":"15","title":"Gerund / Infinitive","level":"Ứng dụng","time":"25 phút","summary":"Chọn V-ing hoặc to V sau động từ, giới từ và tính từ.","theory":["Gerund là V-ing dùng như danh từ; infinitive là to + V.","Một số động từ theo sau bởi V-ing như enjoy, avoid, finish, keep.","Một số động từ theo sau bởi to V như want, decide, hope, plan.","Gerund nhấn hoạt động như một danh từ; infinitive thường nhấn mục đích, dự định hoặc hành động hướng tới.","Một số động từ đổi nghĩa khi đi với V-ing hoặc to V như remember, stop, try."],"formulas":["verb + V-ing","verb + to V","preposition + V-ing","verb + V-ing","verb + to V","preposition + V-ing"],"examples":[{"en":"I enjoy reading books.","vi":"Enjoy đi với V-ing."},{"en":"She decided to study abroad.","vi":"Decide đi với to V."},{"en":"I stopped smoking last year.","vi":"Stop + V-ing nghĩa là dừng hẳn việc hút thuốc."},{"en":"I stopped to call my mother.","vi":"Stop + to V nghĩa là dừng lại để làm việc khác."}],"mistakes":["Sau giới từ dùng V-ing: interested in learning, good at speaking.","Một số động từ đổi nghĩa theo dạng sau: remember doing khác remember to do.","Sau giới từ dùng V-ing, không dùng to V.","Không học máy móc mọi động từ; cần học theo cụm verb pattern."],"exercises":[{"prompt":"We decided ___ the conference until next month.","options":["postpone","postponing","to postpone","postponed"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to postpone."},{"prompt":"Ms. Rivera enjoys ___ with international clients.","options":["work","working","to work","worked"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - working."},{"prompt":"The manager agreed ___ the proposal again.","options":["review","reviewing","to review","reviewed"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to review."},{"prompt":"Employees are responsible for ___ their passwords secure.","options":["keep","keeping","to keep","kept"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - keeping."},{"prompt":"The company plans ___ a new branch overseas.","options":["open","opening","to open","opened"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to open."},{"prompt":"Please avoid ___ confidential information by email.","options":["send","sending","to send","sent"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - sending."},{"prompt":"Mr. Kim offered ___ us with the presentation.","options":["help","helping","to help","helped"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to help."},{"prompt":"The director suggested ___ the budget before approval.","options":["revise","revising","to revise","revised"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - revising."},{"prompt":"We look forward to ___ you at the annual conference.","options":["see","seeing","to see","saw"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - seeing."},{"prompt":"The technician refused ___ the equipment without proper authorization.","options":["repair","repairing","to repair","repaired"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to repair."}]}', 15, 'published'),
  ('grammar', 'cau-hoi', 'Nền tảng', NULL, 'Câu hỏi', 'Tạo Yes/No questions, Wh-questions, tag questions và câu hỏi gián tiếp.', '{"id":"cau-hoi","order":"16","title":"Câu hỏi","level":"Nền tảng","time":"22 phút","summary":"Tạo Yes/No questions, Wh-questions, tag questions và câu hỏi gián tiếp.","theory":["Yes/No questions đảo trợ động từ lên trước chủ ngữ.","Wh-questions dùng từ hỏi như what, when, where, why, who, how.","Câu hỏi gián tiếp dùng trật tự câu kể, không đảo trợ động từ như câu hỏi trực tiếp.","Câu hỏi tiếng Anh cần xác định có động từ be, trợ động từ, modal verb hay động từ thường để đảo đúng.","Câu hỏi lịch sự thường dùng indirect question với trật tự câu kể."],"formulas":["Auxiliary + S + V?","Wh-word + auxiliary + S + V?","Could you tell me + wh-word + S + V?","auxiliary + subject + base verb?","Wh-word + auxiliary + subject + verb?","Could you tell me + clause?"],"examples":[{"en":"Do you like English?","vi":"Yes/No question với trợ động từ do."},{"en":"Where does she live?","vi":"Wh-question với does."},{"en":"How long have you studied English?","vi":"How long đi với hiện tại hoàn thành khi hỏi khoảng thời gian đến hiện tại."},{"en":"Could you tell me where the station is?","vi":"Câu hỏi gián tiếp không đảo is ra trước chủ ngữ."}],"mistakes":["Không quên đưa động từ chính về nguyên mẫu sau do/does/did.","Không đảo từ trong câu hỏi gián tiếp: Do you know where he lives?","Không dùng hai trợ động từ sai chỗ như Do you can...?","Không quên trợ động từ do/does/did với động từ thường."],"exercises":[{"prompt":"___ the marketing team finished the campaign plan?","options":["Has","Does","Is","Did"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - Has."},{"prompt":"Where ___ the conference be held this year?","options":["does","is","will","has"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - will."},{"prompt":"___ you send me the updated invoice, please?","options":["Could","Must","Should","May to"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - Could."},{"prompt":"How often ___ the company hold training sessions?","options":["do","does","is","has"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - does."},{"prompt":"You attended yesterday''s meeting, ___?","options":["did you","didn''t you","do you","aren''t you"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - didn''t you."},{"prompt":"Could you tell me where the nearest copy room ___?","options":["is","does","has","be"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - is."},{"prompt":"Why ___ the shipment delayed?","options":["did","was","has","does"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - was."},{"prompt":"Who ___ responsible for booking the venue?","options":["are","is","do","have"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - is."},{"prompt":"The report is complete, ___?","options":["is it","isn''t it","does it","didn''t it"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - isn''t it."},{"prompt":"Do you know when Mr. Carter ___ back from his business trip?","options":["returns","does return","returning","return"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - returns."}]}', 16, 'published'),
  ('grammar', 'cau-phu-dinh', 'Nền tảng', NULL, 'Câu phủ định', 'Tạo câu phủ định với not, no, never, hardly và trợ động từ đúng.', '{"id":"cau-phu-dinh","order":"17","title":"Câu phủ định","level":"Nền tảng","time":"20 phút","summary":"Tạo câu phủ định với not, no, never, hardly và trợ động từ đúng.","theory":["Câu phủ định thường dùng not sau trợ động từ hoặc động từ be.","Với động từ thường ở Present Simple/Past Simple, cần do/does/did + not + V nguyên mẫu.","Never, hardly, rarely đã mang nghĩa phủ định hoặc gần phủ định nên không dùng thêm not trong cùng ý.","Phủ định cần đặt not đúng sau trợ động từ hoặc be; với động từ thường cần do/does/did.","Một số từ đã mang nghĩa phủ định như never, hardly, rarely nên tránh dùng thêm not gây double negative."],"formulas":["S + be + not + complement","S + do/does/did + not + base verb","S + have/has + not + V3/ed","subject + be + not","subject + do/does/did + not + base verb","subject + have/has + not + V3"],"examples":[{"en":"She does not like coffee.","vi":"Does not đi với động từ nguyên mẫu like."},{"en":"I have never been to London.","vi":"Never mang nghĩa chưa bao giờ."},{"en":"She does not agree with the plan.","vi":"Does not đi với động từ nguyên mẫu agree."},{"en":"I have never tried this dish.","vi":"Never đã mang nghĩa chưa bao giờ."}],"mistakes":["Không viết She doesn''t likes. Sau doesn''t dùng động từ nguyên mẫu.","Tránh phủ định kép trong tiếng Anh chuẩn: I don''t know anything, không phải I don''t know nothing.","Không viết she doesn''t likes.","Không dùng not never trong tiếng Anh chuẩn."],"exercises":[{"prompt":"The manager did ___ approve the revised budget.","options":["no","not","never","none"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - not."},{"prompt":"We have ___ received confirmation from the supplier.","options":["not","no","none","nothing"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - not."},{"prompt":"There are ___ available seats for the morning session.","options":["no","not","never","neither"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - no."},{"prompt":"Employees should ___ share their passwords with anyone.","options":["no","not","none","nothing"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - not."},{"prompt":"The client has ___ complained about our service before.","options":["never","no","none","not ever"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - never."},{"prompt":"The printer is ___ working properly today.","options":["no","not","none","never"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - not."},{"prompt":"We found ___ errors in the final version of the report.","options":["no","not","never","nothing"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - no."},{"prompt":"Mr. Han hardly ___ misses a team meeting.","options":["ever","never","no","not"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - ever."},{"prompt":"The company does ___ allow smoking inside the building.","options":["not","no","never","none"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - not."},{"prompt":"There is ___ reason to delay the project any further.","options":["no","not","none","never"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - no."}]}', 17, 'published'),
  ('grammar', 'cau-truc-thong-dung', 'Ứng dụng', NULL, 'Cấu trúc thông dụng', 'Ôn các mẫu câu hay gặp như used to, be used to, too/enough, so/such, would rather.', '{"id":"cau-truc-thong-dung","order":"18","title":"Cấu trúc thông dụng","level":"Ứng dụng","time":"24 phút","summary":"Ôn các mẫu câu hay gặp như used to, be used to, too/enough, so/such, would rather.","theory":["Used to + V diễn tả thói quen trong quá khứ không còn đúng ở hiện tại.","Be/get used to + noun/V-ing diễn tả việc quen với điều gì, khác với used to + V.","Too/enough, so/such, prefer và would rather giúp viết câu tự nhiên hơn khi diễn tả mức độ, sở thích và lựa chọn.","Các cấu trúc thông dụng giúp câu tự nhiên hơn nhưng cần phân biệt sắc thái: thói quen cũ, mức độ quá/đủ, kết quả và sở thích.","Nên học cấu trúc theo ví dụ trọn câu thay vì chỉ nhớ công thức rời."],"formulas":["S + used to + base verb","S + be/get used to + noun/V-ing","too + adjective/adverb + to V","adjective/adverb + enough + to V","so + adjective + that + clause","such + adjective + noun + that + clause","would rather + base verb"],"examples":[{"en":"I used to live in Da Nang.","vi":"Trước đây tôi từng sống ở Đà Nẵng, hiện tại có thể không còn."},{"en":"She is used to working under pressure.","vi":"Cô ấy đã quen với việc làm việc dưới áp lực."},{"en":"The room was so quiet that I could hear the clock.","vi":"So + adjective + that diễn tả kết quả."},{"en":"I would rather stay home tonight.","vi":"Would rather + V diễn tả lựa chọn muốn làm hơn."}],"mistakes":["Không nhầm used to + V với be used to + V-ing.","Enough đứng sau tính từ/trạng từ nhưng trước danh từ: old enough, enough time.","Không dùng would rather to stay.","Phân biệt too tired to work và tired enough to sleep."],"exercises":[{"prompt":"I used to ___ by train before I bought a car.","options":["commute","commuting","commuted","to commute"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - commute."},{"prompt":"Ms. Park is used to ___ under pressure.","options":["work","working","worked","to work"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - working."},{"prompt":"The meeting room is too small ___ forty people.","options":["accommodate","accommodating","to accommodate","accommodated"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to accommodate."},{"prompt":"The instructions are clear enough ___ without assistance.","options":["follow","following","to follow","followed"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to follow."},{"prompt":"The presentation was so informative ___ everyone stayed until the end.","options":["that","such","enough","too"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - that."},{"prompt":"It was such a successful event ___ the company decided to hold it again.","options":["so","that","enough","too"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - that."},{"prompt":"I would rather ___ the report today than wait until Monday.","options":["finish","finishing","to finish","finished"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - finish."},{"prompt":"The company had better ___ the issue immediately.","options":["address","addressing","to address","addressed"],"answer":0,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: A - address."},{"prompt":"The new software makes it easier ___ customer information.","options":["manage","managing","to manage","managed"],"answer":2,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: C - to manage."},{"prompt":"The manager asked us to keep ___ the project until it is completed.","options":["work on","working on","to work on","worked on"],"answer":1,"hint":"Look at the words around the blank and choose the correct grammar form.","explanation":"Correct answer: B - working on."}]}', 18, 'published')
